) AS (
  VALUES
    ('2543', 'Utah Department of Workforce Services', 'The Utah Department of Workforce Services (DWS) offers a comprehensive range of services to support job seekers, employers, and individuals seeking assistance. Job seekers can access a robust job board with over 35,000 open positions across various fields, as well as resources for career counseling, training, and workshops.', 'government', NULLIF('https://jobs.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2544', 'Weber Basin Job Corps', 'The Weber Basin Job Corps Civilian Conservation Center, located in Ogden, Utah, offers a variety of career-focused training programs, including advanced emergency dispatch, carpentry, culinary arts, electrical work, and forestry conservation. In addition to career preparation, the center provides students with housing, meals, medical care, and a supportive community to help them succeed in a safe and enriching environment', 'service_provider', NULLIF('https://weberbasin.jobcorps.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2545', 'Clearfield Job Corps', 'The Clearfield Job Corps Center provides free educational and vocational training programs for young adults aged 16-24, offering pathways to high school diplomas, GEDs, and certifications in various technical and career fields. The program emphasizes personal and professional growth, preparing students for successful careers with hands-on training, academic support, and opportunities for advanced career education', 'service_provider', NULLIF('https://clearfield.jobcorps.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2546', 'Talent Ready Utah', '"Talent Ready Utah optimizes efforts made by education and industry partnerships, working collectively to build a highly-skilled workforce while providing students with increased career and education opportunities. Below are some of the programs designed to support that mission. Since the program’s inception, Talent Ready Utah has had a proud tradition of partnering with education and employers across various industries to implement similar workforce development programs. These programs provide students with career exploration while building the talent pipeline for sectors with significant economic impacts on the state.

Talent Ready Utah is an initiative under the Utah System of Higher Education focused on bridging education and industry to develop Utah’s workforce. It collaborates with schools, businesses, and government to offer programs like apprenticeships, career pathways, and short-term training, helping students and workers gain valuable skills for high-demand industries while supporting employers in building strong talent pipelines"', 'service_provider', NULLIF('https://talentready.ushe.edu/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2547', 'USU Remote Online Initiative', 'The Rural Online Initiative provides specialized remote work training to individuals and e-commerce help to rural and agriculture businesses for success in a rapidly changing economy.', 'university', NULLIF('https://extension.usu.edu/remoteworkcertificate/', ''), NULLIF('', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2548', 'Apprenticeship Utah', 'The Utah Apprenticeship Program offers a variety of career-building opportunities, enabling individuals to earn while they learn across industries like healthcare, construction, manufacturing, and IT. Participants gain hands-on experience alongside classroom instruction, preparing them for nationally-recognized credentials and high-paying careers, with potential earnings of up to $60,000 annually after completing their apprenticeship​. The program supports both employers and apprentices, helping businesses develop skilled workers and providing a viable alternative to traditional college paths', 'service_provider', NULLIF('https://apprenticeship.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2549', 'Teen Entrepreneur Support Center', 'The Teen Entrepreneur Support Center is dedicated to empowering young entrepreneurs by providing free resources, mentorship, and support to help them achieve business success. The center connects aspiring teen business owners with experienced mentors from various industries, offering guidance on building, growing, and scaling their ventures. Additionally, the center organizes events, workshops, and networking opportunities to foster a collaborative entrepreneurial community.', 'investor', NULLIF('https://teenentrepreneurship.org/', ''), NULLIF('', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2550', 'Uinta Basin Tech - Entrepreneur Center', 'The Entrepreneur Center at Utah State University''s Uintah Basin campus fosters entrepreneurial leadership by offering classes, internships, and competitions to develop skills such as creativity, self-reliance, and resourcefulness.', 'investor', NULLIF('https://statewide.usu.edu/uintahbasin/ecenter/', ''), NULLIF('cameron.cuch@usu.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2551', 'Brigham Young University (BYU) - Rollins Center', 'The Rollins Center for Entrepreneurship & Technology at Brigham Young University''s Marriott School of Business fosters student innovation and business creation through mentorship, competitions, and experiential learning. It offers resources such as the Sandbox program, which helps students launch their own companies, and the Entrepreneur Founders Organization, providing networking opportunities with successful entrepreneurs. The center''s mission is to inspire confidence and creativity, cultivating vision and innovation among students.', 'university', NULLIF('https://marriott.byu.edu/cet/', ''), NULLIF('cet@byu.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2552', 'Salt Lake Community College (SLCC) - The Mill', 'The Mill is the home of the American dream. This is the place where entrepreneurs come to learn, network, and scale their businesses. Discover how our business incubator can help you expand your business.', 'university', NULLIF('https://themillatslcc.com/', ''), NULLIF('info@themillatmiller.com', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Wasatch']::text[]),
    ('2553', 'Snow College - GRIT Center', 'The GRIT Center for Rural Entrepreneurship at Snow College, established in November 2019 with funding from the Utah State Legislature, provides experiential learning opportunities to help students develop leadership skills and an entrepreneurial mindset. Through diverse programming, including pitch competitions and the Entrepreneurship Seminar Series, students can acquire and practice entrepreneurial skills applicable across various aspects of life. The center is committed to fostering innovation and resourcefulness, encouraging students from all majors to participate in its events and initiatives.', 'university', NULLIF('https://www.snow.edu/offices/grit-center/index.html', ''), NULLIF('snowcollege@snow.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2554', 'Utah Valley University (UVU) Entrepreneur Institute', 'The Entrepreneurship Institute at Utah Valley University''s Woodbury School of Business empowers students to become revenue-generating entrepreneurs by graduation. It connects students with expert mentors and offers hands-on, industry-specific programming, including competitions, workshops, seed funding, and mentoring. The institute also provides resources like the Entrepreneurship Lecture Series and the We Lift program, which supports women entrepreneurs.', 'university', NULLIF('https://www.uvu.edu/woodbury/entrepreneurship/', ''), NULLIF('einstitute@uvu.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2555', 'Southern Utah University (SUU) - Larry H. & Gail Miller Center for Entrepreneurship', 'The Larry H. & Gail Miller Center for Entrepreneurship at Southern Utah University''s Dixie L. Leavitt School of Business offers programs and resources to support students from all majors in developing entrepreneurial skills. Guided by the principles of Educate, Experience, and Elevate, the center provides experiential learning opportunities, mentorship, and events such as speaker series and competitions to help students start, manage, and grow their own businesses.', 'university', NULLIF('https://www.suu.edu/business/entrepreneurship/', ''), NULLIF('entrepreneur@suu.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2556', 'Utah Tech University - Atwood Innovation Center', 'The Business Resource Center (BRC) at Utah Tech University, sponsored by Zions Bank, offers complimentary consultations and services to assist entrepreneurs in launching or expanding their businesses. As a comprehensive support hub, the BRC provides guidance on business planning, marketing strategies, LLC formation, government contracting, and global exporting. Additionally, the center is dedicated to fostering entrepreneurship in Southern Utah''s rural areas, currently serving Washington and Kane Counties.', 'university', NULLIF('https://innovation.utahtech.edu/business-resource-center-at-dsu/', ''), NULLIF('businesshelp@utahtech.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2558', 'Utah State University (USU) Jeffrey D. Clark Center for Entrepreneurship', 'The Jeffrey D. Clark Center for Entrepreneurship at Utah State University''s Jon M. Huntsman School of Business fosters entrepreneurial skills through coursework, internships, and competitions. It provides resources such as mentorship, networking opportunities, and access to legal assistance for patents and trademarks, aiming to cultivate creativity, self-reliance, and resourcefulness among students. The center also hosts the Entrepreneur Leadership Series, featuring prominent entrepreneurs who share insights and experiences with the community.', 'university', NULLIF('https://huntsman.usu.edu/ecenter/', ''), NULLIF('entrepreneurship@usu.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Box Elder', 'Cache', 'Rich']::text[]),
    ('2559', 'Make Salt Lake', 'Make Salt Lake is a nonprofit makerspace in Salt Lake City, Utah, offering members 24/7 access to a variety of tools and workspaces, including 3D printers, laser cutters, CNC mills, woodworking, metalworking, textiles, and electronics labs. It fosters innovation by assisting inventors and entrepreneurs with prototyping, business planning, marketing, patent guidance, and funding opportunities.', 'community', NULLIF('http://makesaltlake.org', ''), NULLIF('info@makesaltlake.org', ''), ARRAY[]::text[], ARRAY['consumer packaged goods', 'manufacturing']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2560', 'Portal Warehousing', 'Portal Warehousing Salt Lake City, located at 1580 S 500 W, offers flexible co-warehousing and logistics spaces tailored for e-commerce, logistics, and growing businesses. With private warehouse units ranging from 250 to 2,500 square feet and short-term, flexible lease terms, Portal provides an adaptable environment to meet diverse operational needs. Amenities include loading equipment, private offices, shipping and receiving services, community events, and daily carrier pickups, all designed to streamline business operations and foster growth.', 'coworking', NULLIF('https://www.join-portal.com/location/salt-lake-city', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['consumer packaged goods']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2561', 'Monarch', 'The Monarch, located in Ogden, Utah, is a vibrant creative hub within the Nine Rails Creative District, offering artist studios, event spaces, and community-focused programming. Situated in a renovated 1920s industrial parking garage, it combines historic charm with modern amenities, providing a unique venue for workshops, markets, and public events. Regular events like Open Studio Nights and specialty markets foster collaboration and engagement between artists and the broader community.', 'community', NULLIF('https://themonarchogden.com/', ''), NULLIF('info@themonarchogden.com', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2562', 'Startup Ogden', 'Startup Ogden, located at 2314 Washington Blvd in Ogden, Utah, is a collaborative coworking space and accelerator program developed through a partnership between Ogden City and Weber State University. It offers flexible workspace options, including hot desks and dedicated desks, as well as conference rooms and an online member network to facilitate connections among entrepreneurs. The facility also houses the Weber State University Wildcat Store and Daily Rise Coffee on the ground floor, providing additional amenities for members and visitors.', 'community', NULLIF('https://startupogden.spaces.nexudus.com/home?&v=latest', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2563', 'Maven CREATE', 'Maven Create supports entrepreneurs by offering a collaborative workspace that encourages networking and personal growth, hosting events and workshops to facilitate community engagement. Located within the Maven District, home to Salt Lake City''s largest community of female-owned small businesses, it provides an environment that champions diversity and local enterprises.', 'community', NULLIF('https://mavencreateslc.com/', ''), NULLIF('', ''), ARRAY['Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities', 'women']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2564', 'Salt Mine', 'Salt Mine Productive Workspace, located at 7984 S 1300 E in Sandy, UT,  launched in 2016 as a home for the start-up, tech, and entrepreneur community of Silicon Slopes. The 20,000sf facility provides flexible community coworking, dedicated desks, private offices, large training and event spaces, a la carte conference rooms all with floor to ceiling whiteboard walls, a built-in coffee shop and is host to many community networking events and the South Valley Chamber of Commerce Business Accelerator Academy.', 'community', NULLIF('https://meetatsaltmine.com/', ''), NULLIF('info@meetatsaltmine.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2565', 'Workbox', 'Workbox is a comprehensive platform offering flexible coworking spaces, accelerator programs, and venture capital services to support entrepreneurs and businesses across various growth stages.', 'community', NULLIF('https://www.workboxcompany.com/', ''), NULLIF('info@workboxcompany.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2566', 'Indie Square', 'Indie Square, established in 2024 and located at 141 East 5600 South, Suite 300, in Murray, Utah, is a mission-driven coworking space and event venue dedicated to supporting the state''s nonprofit community. By offering affordable office spaces, meeting rooms, and event venues, Indie Square fosters collaboration and innovation among nonprofit organizations, enabling them to advance their missions effectively. The facility provides various workspace options, including private offices, dedicated desks, and flexible coworking areas, all designed to cultivate a collaborative environment. Additionally, Indie Square offers amenities such as high-speed internet, printing services, and access to fully equipped meeting rooms, ensuring nonprofits have the necessary resources to operate efficiently.', 'community', NULLIF('https://www.indiesquare.org/', ''), NULLIF('community@indiesquare.org', ''), ARRAY[]::text[], ARRAY['other']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities', 'other']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2567', 'The Shop', 'The Shop Salt Lake City is a coworking space located in downtown Salt Lake City, offering flexible workspaces, private offices, and shared desks tailored to professionals, entrepreneurs, and remote workers. The space fosters collaboration and innovation with modern amenities, a supportive community, and accessibility to the vibrant city center', 'community', NULLIF('https://shopworkspace.com/location/salt-lake-city/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2568', 'Work Hive', 'Work Hive offers coworking spaces in downtown Salt Lake City and Sugar House, providing shared office environments tailored for freelancers, small businesses, and remote workers. Their facilities include private offices, conference rooms, and flexible membership options, fostering a collaborative community to enhance productivity and networking', 'community', NULLIF('https://workhiveslc.com/', ''), NULLIF('hello@workhiveSLC.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2569', 'Church and State', 'Church & State Marketplace, located in downtown Salt Lake City, is a versatile establishment offering a coffee-fueled co-working space and marketplace during the day, and transforming into a vibrant event venue by night. The space features vaulted ceilings, towering arches, and stained glass, creating a unique atmosphere for collaboration, conversation, commerce, and various events.', 'community', NULLIF('https://www.cs1893.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2570', 'Kiln', 'Kiln is a coworking space designed for modern professionals and teams, offering a seamless blend of productivity, lifestyle, and community. With locations in Utah, Idaho, and Colorado, it features flexible memberships, curated amenities like wellness rooms, podcast studios, and event spaces, and hosts networking and wellness programs to foster creativity and collaboration', 'community', NULLIF('https://kiln.com', ''), NULLIF('hello@kiln.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Beaver', 'Davis', 'Garfield', 'Iron', 'Kane', 'Morgan', 'Salt Lake', 'Summit', 'Tooele', 'Utah', 'Wasatch', 'Washington', 'Weber']::text[]),
    ('2571', 'Make Utah', 'MAKE Utah is a coworking and research development space in Pleasant Grove, Utah, designed to support technical startups and product-focused entrepreneurs. It offers access to state-of-the-art prototyping equipment, a network of industry experts, and over 50,000 square feet of collaborative work and innovation space, fostering a vibrant ecosystem for innovation and growth​', 'community', NULLIF('https://makeutah.org/', ''), NULLIF('info@makeutah.org', ''), ARRAY[]::text[], ARRAY['consumer packaged goods', 'manufacturing']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2572', 'The Hub at Bridgerland Technical College', 'The Hub at Bridgerland Technical College is a dedicated resource center designed to support entrepreneurs and small businesses in northern Utah. It provides services like business coaching, training, and networking opportunities to help businesses launch, grow, and thrive. With a focus on innovation and collaboration, The Hub empowers local businesses to achieve their goals and strengthen the community.', 'university', NULLIF('https://thehubatbtech.org/', ''), NULLIF('malexander@btech.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Box Elder', 'Cache', 'Rich']::text[]),
    ('2573', 'Business Resource Center - Utah Tech University', 'The Business Resource Center at Utah Tech University, sponsored by Zions Bank, offers NO-COST business consultations and services to help you launch or grow your business. As a one-stop shop for all your business needs, you can meet with our team to brainstorm your business ideas, write a business plan, fine-tune your marketing strategy, launch an LLC, secure government contracts, export around the globe, find a workplace, find a mentor and much more!', 'university', NULLIF('https://innovation.utahtech.edu/business-resource-center-at-dsu/', ''), NULLIF('businesshelp@utahtech.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2574', 'The Mill Entrepreneurship Center', 'The Mill is the home of the American dream. This is the place where entrepreneurs come to learn, network, and scale their businesses. Discover how our business incubator can help you expand your business.', 'investor', NULLIF('https://themillatslcc.com/', ''), NULLIF('info@themillatmiller.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2575', 'Business Resource Center - Davis Tech College', 'The Business Resource Center  (BRC) at Davis Technical College is an essential partner for business owners and entrepreneurs striving to succeed. Whether you’re launching a new venture or looking to grow an existing business, we provide the tools, expertise, and connections to drive your success. From crafting a solid business plan to offering workforce training and development, identifying funding sources for your startup, or navigating government contracting opportunities, the Business Resource Center serves as the catalyst to help your business thrive. Here are some of the resources we offer: business consulting and mentoring, assistance with government contracting, open lobby workspace, incubator office and shared membership space rentals, conference room rentals, business financial planning, and much more.', 'university', NULLIF('https://brc.davistech.edu/', ''), NULLIF('brc@davistech.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2576', 'Vernal Innovation Hub', 'The Vernal Innovation Hub offers coworking spaces and private offices for entrepreneurs and small businesses, providing essential services like high-speed internet, mail handling, and business development classes. It also hosts the annual "Rise & Thrive Business Speed Pitch" competition to support startups, helping them grow and eventually transition into commercial spaces​', 'investor', NULLIF('https://www.vernalinnovationhub.com/', ''), NULLIF('smillett@vernal.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Daggett', 'Duchesne', 'Uintah']::text[]),
    ('2577', 'Southern Utah University Cedar City Business & Innovation Center', 'Southern Utah University''s Business and Innovation Center (BIC) fosters regional economic growth by offering entrepreneurial support and resources for startups. It provides a range of services, including business planning, marketing, and financing assistance, and plays a key role in advancing innovation through partnerships with local organizations and its accelerator programs', 'university', NULLIF('https://www.suu.edu/regional/bic/', ''), NULLIF('brc@suu.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2578', 'Atwood Innovation Plaza', 'The Utah Tech Innovation Center, also known as Innovation Plaza, is a hub for fostering entrepreneurship and innovation. It provides resources like a makerspace, business guidance, and collaborative opportunities to help students, faculty, and community members develop and commercialize innovative ideas', 'investor', NULLIF('https://innovation.utahtech.edu/', ''), NULLIF('businesshelp@utahtech.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2579', 'Utah Valley University Innovation Center/Academy', 'The UVU Innovation Academy fosters a hands-on learning environment where students collaborate on real-world projects, gaining professional skills while addressing industry challenges. It serves as a hub for creativity and entrepreneurship, connecting students with resources and partnerships to innovate and excel in their careers', 'university', NULLIF('https://www.uvu.edu/innovation/', ''), NULLIF('bgodoy@uvu.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2580', 'Business Technical Assistance Center', 'The Business & Technical Assistance Center (BTAC), located in Price, Utah, offers coworking spaces, business incubation services, and resources for entrepreneurs. With amenities like fiber internet, 24-hour access, commercial kitchen rentals, and flexible office space plans, it aims to foster innovation and economic growth in southeastern Utah through partnerships with local businesses and government initiatives', 'investor', NULLIF('https://www.btac.business/', ''), NULLIF('info@btac.business', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2581', 'Monticello Coworking Space', 'The Monticello Coworking Space, located at 80 North Main Street in Monticello, Utah, offers a professional environment for remote workers, entrepreneurs, and small businesses. Amenities include high-speed Wi-Fi, furnished offices, meeting rooms, privacy booths, a kitchen, and lounge areas. Members enjoy 24/7 access, while non-members can reserve conference rooms and other facilities during business hours.', 'coworking', NULLIF('https://members.monticellocoworking.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2582', 'University of Utah Lassonde Entrepreneurship Institute', 'The Lassonde Entrepreneur Institute at the University of Utah is a nationally recognized hub for entrepreneurship and innovation. It offers a wide range of programs, including workshops, grants, competitions, and residential experiences at Lassonde Studios, supporting students from any discipline to learn, innovate, and launch businesses', 'university', NULLIF('https://lassonde.utah.edu/', ''), NULLIF('lassonde@utah.edu', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'student']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2583', 'Utah Defense Alliance', 'The Utah Defense Alliance (UDA) is dedicated to supporting and advocating for military missions, personnel, and installations in Utah, while promoting the state''s role in national defense. Through collaboration with government, industry, and community partners, UDA ensures a strong defense presence and fosters economic growth within the region.', 'service_provider', NULLIF('https://utahdefensealliance.com/home/', ''), NULLIF('kjsullivan51@yahoo.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2584', 'Escalante City Innovation Center', 'The Escalante City Innovation Center in Utah provides furnished private offices tailored for remote workers, each equipped with dual monitors and laptop docking stations. The center also features a spacious meeting room with a conference table and a wide-screen TV, accommodating collaborative sessions and presentations. Flexible workspace options are available at daily, weekly, and monthly rates to suit various professional needs.', 'incubator', NULLIF('https://www.escalantecity-utah.com/services/escalante-city-innovation-center/', ''), NULLIF('ssteed@escalantecity.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2585', 'Utah Microloan Fund (UMLF)', 'The Utah Microloan Fund (UMLF), established in 1991, is a nonprofit Community Development Financial Institution (CDFI) dedicated to empowering underserved communities across Utah. UMLF provides business training and microloans to entrepreneurs in startup and existing businesses who do not qualify for traditional funding sources, with a focus on low-to-moderate income individuals, women, minorities, and other underserved populations', 'investor', NULLIF('https://www.utahmicroloanfund.org/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2586', '47G - Utah Aerospace & Defense Association', '47G is a collaborative organization based in Utah focused on advancing innovation in the aerospace and defense industries. Through initiatives like the 47G Impact Center, it offers tailored resources to help companies enhance manufacturing processes, improve efficiency, and boost profitability, ultimately supporting job creation and economic growth in Utah''s vibrant aerospace ecosystem​.', 'service_provider', NULLIF('https://www.47g.org/', ''), NULLIF('contact@47g.org', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2587', 'Acceler8 Wasatch', 'Acceler8Wasatch is supported by a group of partners excited to grow Utah''s Innovation and Entrepreneurial ecosystem. This group, originally geographically centered in Northern Utah, is interested in supporting Innovation and Entrepreneurship in all of Utah. While initially focused on the aerospace and defense industry, it is welcoming other industries, technologies, and markets.', 'service_provider', NULLIF('https://www.acceler8wasatch.com/', ''), NULLIF('info@uammi.org', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2588', 'Mountain Land Association of Governments'' Revolving Loan Fund (RLF)', 'The Revolving Loan Fund (RLF), facilitated by Wasatch County in collaboration with the Mountainland Association of Governments (MAG), provides "gap" and startup financing to qualified businesses within the Mountainland region of Utah, encompassing Heber Valley. The primary objective of this fund is to stimulate local business expansion and generate permanent, long-term employment opportunities.', 'investor', NULLIF('https://www.gohebervalley.com/Revolving-loan/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2589', 'Revolving Loan Fund Program (RLF) - South Eastern Utah', 'The Revolving Loan Fund (RLF), administered by the Southeastern Utah Association of Local Governments (SEUALG), provides financial assistance to startups and expanding businesses in Carbon, Emery, Grand, and San Juan counties that may not qualify for traditional financing. The program aims to stimulate economic development and job creation within these communities.', 'investor', NULLIF('https://seualg.utah.gov/index.php/economic-development/revolving-loan-fund-rlf/', ''), NULLIF('cotto@seualg.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2590', 'Utah Department of Agriculture & Food', 'The Utah Department of Agriculture and Food (UDAF) works to support and enhance Utah''s agriculture and food industries while ensuring a high-quality food supply. Key programs include the International Trade Program, Utah''s Own marketing initiative, Specialty Crop Block Grants, and community-focused efforts such as Farm to School education. These initiatives promote economic development, sustainability, and public awareness about local agriculture.', 'government', NULLIF('https://ag.utah.gov/', ''), NULLIF('agriculture@utah.gov', ''), ARRAY['Rural']::text[], ARRAY['agriculture']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2591', 'Revolving Loan Fund Program (RLF) - R6', 'The Revolving Loan Fund (RLF), administered by the R6 Regional Council, offers "gap financing" to support new and expanding businesses within Juab, Millard, Piute, Sanpete, Sevier, and Wayne counties in Utah. This program provides loans ranging from $20,000 to $250,000, aiming to stimulate economic growth and job creation in the region.', 'investor', NULLIF('https://r6.utah.gov/edd-board-economic-development-district-board/revolving-loan-fund-rlf/', ''), NULLIF('arosquist@R6.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2592', 'Utah Small Business Credit Initiative (USBCI)', 'The Utah Small Business Credit Initiative (USBCI), administered by the Governor''s Office of Economic Opportunity, is a statewide program designed to enhance access to capital for small businesses, particularly those in underserved communities.', 'investor', NULLIF('https://business.utah.gov/usbci/', ''), NULLIF('capitalaccess@utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2593', 'Cynosure', 'The Cynosure Group is an independent alternatives asset manager and advisor that makes long-term investments on behalf of families, foundations, and other like-minded institutions. Based in Salt Lake City, Utah.', 'investor', NULLIF('https://cynosuregroup.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2594', 'Cross Creek', 'Cross Creek, founded in 2006, is a venture capital firm that invests in exceptional venture-backed companies with the potential to become successful public entities. The firm focuses on sectors such as consumer internet, enterprise software, and cybersecurity, partnering with innovative businesses to support their growth and transition from private to public markets. Cross Creek''s portfolio includes companies like AppDynamics, Braze, and HubSpot, reflecting its commitment to identifying and nurturing high-growth ventures.', 'investor', NULLIF('https://crosscreek.vc/', ''), NULLIF('info@crosscreek.vc', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2595', 'Savory Fund', 'Savory Fund is a private equity firm specializing in the rapid expansion of emerging restaurant concepts by providing capital investment and operational expertise. Founded by Andrew and Shauna Smith, the Lehi, Utah-based firm manages over $750 million in assets and has successfully closed three funds: two at $100 million each in 2020 and 2021, and a third at $200 million in January 2024. Savory Fund''s portfolio includes brands such as Swig, R&R BBQ, and Via 313 Pizzeria, with operations across multiple states.', 'investor', NULLIF('https://savoryfund.com/', ''), NULLIF('info@savoryfund.com', ''), ARRAY[]::text[], ARRAY['hospitality and food services']::text[], ARRAY['mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2596', 'Mercato Partners', 'Mercato Partners, founded in 2007 and based in Cottonwood Heights, Utah, is a private equity firm specializing in growth-stage investments across technology, consumer brands, and food and beverage sectors. The firm manages over $1.6 billion in assets and operates multiple funds, including the Traverse Growth Fund, Savory Restaurant Fund, Prelude Venture Fund, and Alpha Secondary Fund. Mercato Partners has invested in companies such as Central Logic and Cotopaxi, providing both capital and strategic guidance to foster business expansion.', 'investor', NULLIF('https://www.mercatopartners.com/', ''), NULLIF('admin@mercatopartners.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2597', 'Utah''s Own - Local Food Production', 'Utah''s Own is a program by the Utah Department of Agriculture and Food designed to connect consumers with local farmers, ranchers, and artisans. It encourages purchasing locally produced goods to support community businesses, enhance product quality, and preserve agricultural spaces. The initiative includes a directory of members, such as farms, specialty food producers, and artisans, and promotes local goods through marketing campaigns and events like farmers'' markets and artisan festivals.', 'service_provider', NULLIF('https://utahsown.org/', ''), NULLIF('utahsown@utah.gov', ''), ARRAY['Rural']::text[], ARRAY['agriculture']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['entrepreneurship-communities', 'late-stage-growth', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2598', 'Sorenson Impact Fund', 'The Sorenson Impact Foundation, based in Salt Lake City, Utah, invests in innovative social entrepreneurs addressing global challenges, with a focus on underserved communities. The foundation allocates 100% of its assets to impact investments, supporting ventures that promote economic mobility, access to quality education and healthcare, and environmental sustainability. Their portfolio includes program-related investments (PRIs) and mission-related investments (MRIs) across various sectors and geographies.', 'investor', NULLIF('https://sorensonimpactfoundation.org/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'fundraising']::text[], ARRAY['funding', 'other']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2599', 'Renewable Tech Ventures', 'RenewableTech Ventures is a venture capital firm that invests in early-stage innovations within sectors such as energy, clean technology, green materials, and other related fields. Their investment focus spans the United States and Canada, particularly targeting regions underserved by venture capital. With a combined 80 years of experience in venture capital and clean tech, the team offers not only financial support but also market intelligence, active board participation, and access to an extensive international network of industry contacts, technology leaders, and co-investors', 'investor', NULLIF('https://www.renewablevc.com/', ''), NULLIF('info@renewablevc.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'fundraising']::text[], ARRAY['funding', 'other']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2600', 'Pitted Ventures', 'Pitted Ventures, founded in 2021 and based in Sandy, Utah, is a growth capital investment firm specializing in emerging consumer brands. Pitted Ventures distinguishes itself by offering not only financial capital but also a suite of mission-critical services through its affiliates, Pitted Labs and Pitted Logistics, which provide e-commerce channel management, logistics, fulfillment, and enhanced data analytics.', 'investor', NULLIF('https://pittedventures.com/', ''), NULLIF('inquiries@pittedventures.com', ''), ARRAY[]::text[], ARRAY['consumer packaged goods']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2601', 'BIO Utah', 'BioUtah is a trade association dedicated exclusively to supporting the state''s life sciences sector, which includes medical devices, biopharmaceuticals, diagnostics, and related fields. The organization fosters industry growth through networking opportunities, advocacy for favorable public policies, workforce development programs, and efforts to attract investments, positioning Utah as a hub for healthcare innovation and economic development.', 'service_provider', NULLIF('https://bioutah.org/', ''), NULLIF('kelvyn@bioutah.org', ''), ARRAY['Any']::text[], ARRAY['life sciences and healthcare', 'software and information technology']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2602', 'Signal Peak Ventures', 'Signal Peak Ventures (SPV) is a Salt Lake City-based venture capital firm that invests in early-stage technology companies across the United States. SPV focuses on partnering with passionate entrepreneurs to build leading companies with enduring value. Their portfolio includes a diverse range of technology-driven businesses, reflecting their commitment to fostering innovation and growth.', 'investor', NULLIF('https://www.spv.com/', ''), NULLIF('info@spv.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2603', 'Album', 'Album VC, founded in 2014 and based in Lehi, Utah, is a venture capital firm that invests in early-stage technology startups across the United States. The firm focuses on sectors such as software, healthcare services, SaaS, life sciences, and oncology, with a portfolio that includes companies like Andela, Degreed, and Podium. In June 2022, Album VC announced the launch of a $200 million fund, significantly expanding its capacity to support innovative startups.', 'investor', NULLIF('https://www.album.vc/', ''), NULLIF('hello@album.vc', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2604', 'Epic Ventures', 'EPIC Ventures, founded in 1994 in Salt Lake City, Utah, is a venture capital firm specializing in early-stage technology investments across sectors such as software-as-a-service (SaaS), healthcare, biotech, security, fintech, and the future of work. The firm has a history of successful investments, including companies like Ancestry, Instructure, Health Catalyst, and Recursion Pharmaceuticals. In September 2024, EPIC Ventures partnered with the University of Utah to launch University of Utah Ventures, Powered by EPIC, aiming to drive regional innovation by supporting early-stage technology companies.', 'investor', NULLIF('https://www.epicvc.com/', ''), NULLIF('info@epicvc.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2605', 'Convoi Ventures', 'Convoi Ventures, founded in 2021, is a Utah-based pre-seed venture capital firm dedicated to identifying and funding the state''s emerging startups. The firm focuses on sectors such as consumer technology, fintech, and SaaS, emphasizing investments in founders who demonstrate rapid progress with minimal resources. By fostering a community-centric approach, Convoi Ventures regularly organizes high-quality events to cultivate strong relationships among founders and limited partners, thereby strengthening Utah''s entrepreneurial ecosystem.', 'investor', NULLIF('https://www.convoiventures.com/', ''), NULLIF('info@convoiventures.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2606', 'Pelion Ventures', 'Pelion Venture Partners, founded in 1986 and based in Salt Lake City, Utah, is a venture capital firm specializing in early-stage investments in software-based technology companies across the United States. The firm focuses on sectors such as B2B SaaS, fintech, marketplaces, cloud computing, and security, with a portfolio that includes successful companies like Cloudflare, Divvy, and Weave. In October 2021, Pelion closed its seventh fund at $365 million, exceeding its initial target of $250 million, to continue supporting innovative technology founders.', 'investor', NULLIF('https://pelionvp.com/', ''), NULLIF('info@pelionvp.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah']::text[]),
    ('2607', 'Grix', 'Grix Venture Capital, based in Salt Lake City, Utah, focuses on pre-seed investments in enterprise software startups. The firm supports companies from "Day Zero" with funding and expertise, particularly in software, artificial intelligence, and B2B solutions, across North America and Europe', 'investor', NULLIF('https://www.grix.vc/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2608', 'BIOHive Utah', 'BioHive is a public-private partnership in Utah aimed at fostering innovation and growth within the life sciences and healthcare industries. It connects startups, established companies, investors, and academic institutions, positioning Utah as a leader in medical research and digital health solutions.', 'service_provider', NULLIF('https://www.biohive.com/', ''), NULLIF('', ''), ARRAY['Any']::text[], ARRAY['life sciences and healthcare']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2609', 'Tandem Ventures', 'Tandem Ventures is a Draper, Utah-based venture capital firm specializing in early-stage investments. The firm supports startups across industries, focusing on financial software, logistics, and business productivity solutions.', 'investor', NULLIF('https://tandeminvest.com/', ''), NULLIF('team@tandeminvest.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2610', 'Peterson Ventures', 'Peterson Ventures is a Utah-based seed-stage venture capital firm specializing in early investments in startups, particularly in SaaS, digital commerce, fintech, and healthtech sectors. Known for its founder-first approach, the firm provides funding between $250,000 and $1 million and strategic support to help entrepreneurs navigate growth challenges; its portfolio includes companies like Allbirds, Ethos, and Lucid Software', 'investor', NULLIF('https://www.petersonventures.com/', ''), NULLIF('contact@petersonventures.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2611', 'Kickstart Fund', 'Kickstart Fund, established in 2008, is a venture capital firm based in Cottonwood Heights, Utah, specializing in seed-stage investments within the Mountain West region. The firm focuses on sectors such as B2B SaaS, fintech, healthtech, and consumer products, aiming to support early-stage startups through capital and strategic guidance. Notable companies in their portfolio include Podium, SonderMind, and Lucidchart, reflecting their commitment to fostering innovation and growth in the regional startup ecosystem.', 'investor', NULLIF('https://www.kickstartfund.com/', ''), NULLIF('info@kickstartfund.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2612', 'World Trade Center Utah', 'World Trade Center Utah (WTC Utah) is a nonprofit organization dedicated to accelerating the growth of Utah companies by connecting them to global markets. Affiliated with the World Trade Centers Association, WTC Utah offers services such as market expansion assistance, supply chain optimization, and access to grants, aiming to make international business as accessible as local commerce.', 'service_provider', NULLIF('https://www.wtcutah.com/', ''), NULLIF('info@wtcutah.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2613', 'Red Rock Angels', 'Red Rock Angels is an angel investor group based in St. George, Utah, dedicated to providing capital, mentorship, and resources to early-stage companies across various sectors, including technology, healthcare, and consumer products. The group comprises experienced entrepreneurs and accredited investors passionate about fostering entrepreneurship and economic growth in Southern Utah. They are currently accepting applications from entrepreneurs seeking funding and support for their ventures.', 'investor', NULLIF('https://redrockangels.com/', ''), NULLIF('info@redrockangels.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2614', 'Salt Lake Angels', 'The Salt Lake City Angels (SLCA) is an angel investment group that provides a platform for investors to collaboratively research and evaluate early-stage companies, offering both capital and mentorship to selected startups. SLCA emphasizes core values such as mutual respect, human dignity, ethical business practices, diversity, and humility in all interactions with members and entrepreneurs. Their strategy focuses on a broad investment thesis, fostering a diverse membership of accredited investors, maintaining a robust pipeline of quality startups, conducting comprehensive due diligence, and ensuring effective organizational administration.', 'investor', NULLIF('https://slcangels.org/', ''), NULLIF('support@slcangels.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2615', 'Utah Manufacturers Association', 'The Utah Manufacturers Association (UMA) is the leading alliance for Utah''s manufacturing community, representing over 1,200 manufacturing and service providers statewide. UMA offers its members a range of benefits, including networking opportunities, legislative advocacy, safety training, and access to industry-specific resources. The association is committed to addressing the unique challenges faced by manufacturers, providing support from internal operations to representation at the Utah State Capitol.', 'service_provider', NULLIF('https://manufacturingutah.com/', ''), NULLIF('info@manufacturingutah.com', ''), ARRAY['Any']::text[], ARRAY['manufacturing']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2616', 'Park City Angels', 'The Park City Angels is Utah''s largest and most active angel investment group, comprising over 85 accredited investors who provide early-stage capital to high-growth companies across the United States. Since its inception in 2008, the group has invested more than $85 million in over 1,275 individual investments, supporting ventures across various industries. Beyond financial backing, members offer mentorship, industry expertise, and valuable connections to entrepreneurs, aiming to foster innovation and economic growth', 'investor', NULLIF('https://www.parkcityangels.com/', ''), NULLIF('info@parkcityangels.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2617', 'RevRoad', 'RevRoad, founded in 2017 and based in Provo, Utah, is a venture services firm focused on accelerating the growth of early-stage startups. Entrepreneurs benefit from RevRoad''s comprehensive support in navigating key growth stages.', 'investor', NULLIF('https://www.revroad.com/', ''), NULLIF('info@revroadcapital.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2618', 'Wildcat MicroFund', 'The Wildcat MicroFund, established in 2018 at Weber State University, provides early-stage entrepreneurs across Utah with grants of up to $3,000 to support the launch and growth of their businesses. Unlike traditional business competitions, the fund emphasizes execution by awarding funding based on the completion of specific milestones, utilizing frameworks like Lean Startup and Business Model Canvas to validate scalable business models. Since its inception, the Wildcat MicroFund has awarded over $780,000 to more than 300 entrepreneurs, fostering high-growth business opportunities throughout the state.', 'investor', NULLIF('https://www.weber.edu/wildcat-microfund/', ''), NULLIF('wildcatmicrofund@weber.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2619', 'Utah MEP', 'The Utah Manufacturing Extension Partnership (Utah-MEP) is the state''s official representative of the MEP National Network, dedicated to enhancing the competitiveness of Utah''s manufacturing sector. Utah-MEP offers tailored services, including operational assessments, workforce training, and technology integration, to help manufacturers improve productivity and profitability. By collaborating with industry experts and leveraging public and private resources, Utah-MEP aims to foster growth and innovation within the state''s manufacturing community.', 'service_provider', NULLIF('https://utah-mep.org/', ''), NULLIF('info@utah-MEP.org', ''), ARRAY['Any']::text[], ARRAY['manufacturing']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2620', 'iHub', 'The Innovation Hub of Utah County (iHub), established in 2023, is a nonprofit incubator dedicated to assisting young entrepreneurs in Utah County. Located at 389 1300 W, Pleasant Grove, UT 84062, iHub serves as a central resource center for early-stage startups, offering a vast network of mentors to help entrepreneurs overcome obstacles and foster growth. The organization provides tangible solutions and expert advice, acting as a launchpad for entrepreneurs with validated business ideas, equipping them with the necessary tools and support to navigate the complexities of launching and scaling their ventures in today''s competitive landscape.', 'investor', NULLIF('https://www.ihubutah.org/', ''), NULLIF('', ''), ARRAY['Student']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'start-a-business', 'student']::text[], ARRAY['Utah']::text[]),
    ('2621', 'iMpact Utah', 'iMpact Utah is a nonprofit organization dedicated to enhancing the performance and profitability of Utah''s manufacturing sector. They offer comprehensive consulting and training services in areas such as operations optimization, leadership development, sales, marketing, automation, and cybersecurity. By working closely with businesses, iMpact Utah aims to drive measurable improvements, contributing to the state''s economic growth and the creation of high-quality jobs.', 'service_provider', NULLIF('https://www.impactutah.org/', ''), NULLIF('info@impactutah.org', ''), ARRAY['Any']::text[], ARRAY['manufacturing']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2622', 'Get Started: Business Idea Challenge', 'The Utah Startup State Initiative''s "Get Started: Business Idea Challenge" is a milestone grant program designed to help Utah residents validate and develop early-stage business ideas. Participants can receive up to $500 in non-equity funding to achieve specific milestones, such as idea validation, prototyping, or marketing, within 30-90 days. This supportive environment encourages entrepreneurs to present their concepts without the high pressure of traditional pitch competitions.', 'investor', NULLIF('https://startup.utah.gov/get-started/', ''), NULLIF('startup@utah.gov', ''), ARRAY['Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'fundraising']::text[], ARRAY['funding', 'multicultural', 'new-american', 'rural', 'start-a-business', 'student', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2623', 'Sillicon Slopes', 'Silicon Slopes is a nonprofit organization that empowers Utah''s startup and tech community by providing resources, events, and networking opportunities to foster innovation and entrepreneurship. It serves as a central hub for Utah companies and entrepreneurs, offering connections, education, and community engagement to support business growth and development. Notable initiatives include the annual Silicon Slopes Summit, which brings together industry leaders and professionals to discuss trends and opportunities in technology and business.', 'service_provider', NULLIF('https://www.siliconslopes.com/', ''), NULLIF('', ''), ARRAY['Any']::text[], ARRAY['software and information technology']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['any', 'entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2624', 'EVENT: Utah Tech Week', 'Utah Tech Week is a community-driven celebration of technology and innovation. The event features a diverse array of experiences and gatherings hosted by startups, venture capital firms, and community organizations, aiming to foster "happy collisions" that lead to friendships, partnerships, and business deals. Participation is open to all, with no cost to attend or sponsor, encouraging widespread involvement in building Utah''s tech scene.', 'event', NULLIF('https://www.utahtechweek.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2625', 'EVENT: Mountain West Capital Network', 'MountainWest Capital Network (MWCN) is Utah''s premier business networking organization dedicated to supporting entrepreneurial success and facilitating the flow of financial, intellectual, and human capital. MWCN hosts signature events such as the Utah 100 Awards, which recognize the state''s fastest-growing companies, and the Deal Flow Report, summarizing equity-related financial transactions and mergers and acquisitions in Utah. Through these initiatives, MWCN fosters a vibrant business community by celebrating achievements, providing educational opportunities, and facilitating strong business relationships among its members.', 'event', NULLIF('https://www.mwcn.org/', ''), NULLIF('info@mwcn.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2626', 'Women Tech Counsel', 'The Women Tech Council (WTC) is a national organization dedicated to amplifying the economic impact of women in the technology sector by developing programs that support the talent pipeline from high school to executive leadership roles. Serving a community of over 10,000 professionals, WTC offers mentoring, visibility, opportunities, and networking to both women and men in technology. Their initiatives include the SheTech program, which engages high school girls in STEM, and the Women Tech Awards, recognizing outstanding contributions by women in tech.', 'service_provider', NULLIF('https://www.womentechcouncil.com/', ''), NULLIF('info@womentechcouncil.org', ''), ARRAY['Women']::text[], ARRAY['software and information technology']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['entrepreneurship-communities', 'late-stage-growth', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2627', 'EVENT: Business Forward', 'Utah Business Forward is a premier conference tailored for executives seeking actionable strategies to advance their businesses. Attendees will benefit from insights shared by industry experts, in areas of acquisitions, AI, branding, entrepreneurship, people & culture, and others.', 'event', NULLIF('https://forward.utahbusiness.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery']::text[]),
    ('2628', 'Small Business Administration (SBA)', 'The U.S. Small Business Administration (SBA) is a government agency dedicated to supporting entrepreneurs and small businesses through a range of resources and programs. It provides services like business financing, disaster assistance, government contracting support, and entrepreneurial education to help businesses start, grow, and succeed. With a mission to strengthen the economy by empowering small businesses, the SBA serves as a vital partner for businesses navigating challenges and pursuing opportunities.', 'investor', NULLIF('https://www.sba.gov/', ''), NULLIF('answerdesk@sba.gov', ''), ARRAY['Any', 'Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['any', 'funding', 'late-stage-growth', 'multicultural', 'new-american', 'rural', 'start-a-business', 'student', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2629', 'EVENT: One Utah Summit', 'The One Utah Summit is an annual gathering that brings together Utah''s business, nonprofit, and government leaders to discuss and strategize on the state''s economic development and future. Historically, the summit has been held biannually, with events in both northern and southern Utah. However, starting in 2025, the summit will transition to a single, three-day event each October at Southern Utah University (SUU) in Cedar City.', 'event', NULLIF('https://oneutahsummit.utah.gov/', ''), NULLIF('lisonbee@suu.edu', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2630', 'EVENT: Silicon Slopes Tech Summit', 'The Silicon Slopes Summit is one of North America''s premier tech and business events, bringing together industry leaders, entrepreneurs, and innovators for networking, keynote speeches, and workshops. The upcoming Summit is scheduled for January 13th to 17th, 2025, with events planned at both the UCCU Center at Utah Valley University and the Salt Palace Convention Center in Salt Lake City. Attendees can expect a diverse agenda featuring world-class speakers, networking opportunities, and specialized tracks such as Startup Alley, focusing on emerging businesses and investment opportunities.', 'event', NULLIF('https://www.siliconslopes.com/summit', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2631', 'Vision Iron County', 'Vision Iron County (VIC) is a nonprofit organization dedicated to guiding the sustainable growth and development of Iron County, Utah. Established in 2017, VIC brings together community stakeholders to address key areas such as natural resource management, land use planning, transportation, and economic development. Through initiatives like the Vision 2050 survey, VIC gathers resident input to align community priorities with future planning efforts.', 'investor', NULLIF('https://visionironcounty.org/', ''), NULLIF('office@cedarcitychamber.org', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2632', 'Tech Ridge', 'Tech Ridge is a 180-acre mixed-use development in St. George, Utah, transforming the former municipal airport site into a hub for innovative tech companies, residential communities, and recreational spaces. The master plan includes over one million square feet of office space, diverse retail zones, and a variety of housing options, all integrated with 60 acres of trails, parks, and open spaces to promote a dynamic social lifestyle. Current developments feature the Planstin Building, Hangar C, and the Container Park, with companies like Zonos and Intergalactic establishing their presence, contributing to the region''s economic growth and technological advancement.', 'investor', NULLIF('https://techridge.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2633', 'EVENT: What''s Up Down South - Economic Summit', 'The "What''s Up Down South" Economic Summit is Southern Utah''s premier business gathering, offering insights into regional economic trends and strategic planning. The 29th annual summit is scheduled for January 9, 2025, at the Dixie Convention Center in St. George, Utah, featuring keynote speakers, skill-based workshops, and networking opportunities. This event is designed to equip business and community leaders with the latest economic information to help plan for the year ahead.', 'event', NULLIF('https://whatsupdownsouth.org/', ''), NULLIF('', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2634', 'EVENT: Grand Summit Moab', 'The Grand Summit Moab is an annual business conference held in Moab, Utah, bringing together regional business owners and stakeholders to discuss the area''s economic future. The event features keynote speakers, panel discussions, and breakout sessions on topics such as sustainable tourism, local economic development, and community engagement.', 'event', NULLIF('https://www.grandsummitmoab.com/', ''), NULLIF('Nicole@powerhouse.events', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2635', 'EVENT: Raising Kane Business Summit', 'The Raising Kane Business Summit is Kane County''s premier business event, bringing together top leaders and business owners to support the county''s economic development. Hosted annually in Kanab, Utah, at the Kanab Event Center, the summit provides a platform for networking, innovation, and discussions on influential topics impacting the local economy.', 'event', NULLIF('https://www.raisingkanesummit.com/', ''), NULLIF('', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'taxes-and-finance']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2636', 'Utah Division of Outdoor Recreation', 'The Utah Division of Outdoor Recreation, part of the Department of Natural Resources, promotes healthy, active lifestyles by providing access to outdoor spaces and recreational activities. It oversees programs such as boating safety, off-highway vehicle (OHV) education, and trail development, emphasizing safety, education, stewardship, and sustainable visitation. In addition to these efforts, the division works to recruit outdoor recreation businesses, further enhancing the state''s outdoor economy. It also administers grants like the Utah Outdoor Recreation Grant (UORG) to support the development of recreational infrastructure that bolsters local economies.', 'community', NULLIF('https://recreation.utah.gov/', ''), NULLIF('jasoncurry@utah.gov', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'hospitality and food services']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2637', 'Utah Tourism Association', 'The Utah Tourism Industry Association (UTIA) serves as the collective voice of Utah''s visitor economy, advocating for and educating on behalf of the state''s tourism sector. It offers resources such as legislative updates, research tools, and networking opportunities to support businesses and organizations involved in Utah''s tourism industry.', 'community', NULLIF('https://utahtourism.org/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'hospitality and food services']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2638', 'Utah Film Commission', 'The Utah Film Commission promotes the state as a prime location for film, television, and commercial productions, offering support such as location scouting, crew resources, and incentive programs. Celebrating its 50th anniversary in 2024, the commission continues to foster the development of local talent and showcase Utah''s diverse landscapes to the entertainment industry.', 'community', NULLIF('https://film.utah.gov/', ''), NULLIF('film@utah.gov', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'hospitality and food services']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2639', 'Utah Office of Tourism', 'The Utah Office of Tourism promotes tourism throughout the state by showcasing Utah’s natural wonders, cultural heritage, and recreational opportunities. It supports local economies through strategic marketing, partnerships, and the development of tourism-related initiatives. By highlighting Utah as a premier destination, the office aims to attract visitors and enhance their experiences while exploring the state.', 'community', NULLIF('https://travel.utah.gov/', ''), NULLIF('info@visitutah.com', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'hospitality and food services']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities', 'other']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2640', 'Visit Utah', 'Visit Utah is the official travel guide for exploring Utah’s diverse landscapes, national parks, and cultural experiences. It offers resources for planning trips, highlighting outdoor adventures, scenic byways, and unique destinations across the state. Through its efforts, Visit Utah showcases the state’s natural beauty and vibrant communities, inviting visitors to discover all it has to offer.', 'community', NULLIF('https://www.visitutah.com/', ''), NULLIF('info@visitutah.com', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'hospitality and food services']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities', 'other']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2641', 'Kinect Capital', 'Kinect Capital, established in 1983 as an educational nonprofit, is dedicated to enhancing the investability of new entrepreneurs and connecting them with diverse capital sources. Through a culture of kinship, it facilitates meaningful connections among entrepreneurs, mentors, and investors across various industries.', 'investor', NULLIF('https://kinectcapital.org/', ''), NULLIF('info@kinectcapital.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2642', 'Veteran-Owned Business Registration Utah', 'The Utah Veteran-Owned Business Registry is an initiative by the Utah Department of Veterans and Military Affairs (UDVMA) and the Veteran Business Resource Center (VBRC) at Salt Lake Community College, launched in January 2023. This registry promotes veteran-owned businesses across Utah, enabling the public to easily search for and support these enterprises. Veteran entrepreneurs can register their businesses, enhancing visibility and fostering community support. The registry verifies veteran status and business licenses to ensure authenticity.', 'community', NULLIF('https://vbr.veterans.utah.gov/s/', ''), NULLIF('vbrc@slcc.edu', ''), ARRAY['Veteran']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['entrepreneurship-communities', 'veteran']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2643', 'Grow Utah', 'Grow Utah, founded in 2005, is a nonprofit organization dedicated to accelerating the creation of innovative, entrepreneur-led, high-growth businesses to strengthen and expand Utah''s economy. The organization aims to create a robust entrepreneurial ecosystem by fostering talent, driving innovation, aligning community resources, and ensuring funding for promising products and businesses.', 'investor', NULLIF('https://www.growutah.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['consumer packaged goods', 'manufacturing']::text[], ARRAY['validation', 'mvp', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2644', 'Veteran Business Resource Center (VBRC) Utah', 'The Utah Veteran Business Resource Center (VBRC) offers a range of services, including one-on-one business advising, assistance with business plan development, financial analysis, and marketing strategies. Additionally, the center provides educational programs like the Startup Training Resources to Inspire Veteran Entrepreneurship (STRIVE) program.', 'mentor', NULLIF('https://utahvbrc.org/', ''), NULLIF('vbrc@slcc.edu', ''), ARRAY['Veteran']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'launched', 'traction']::text[], ARRAY['entrepreneurship-communities', 'marketing-and-sales', 'start-a-business', 'veteran']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2645', 'Altitude Labs', 'Altitude Lab, established in 2020 through a collaboration between Recursion and the University of Utah’s PIVOT Center, is a health care incubator dedicated to fostering a diverse community of entrepreneurs in Utah. The organization provides over 5,000 square feet of professionally managed lab space, including shared cell culture facilities and state-of-the-art molecular biology instrumentation, to support early-stage life science and health care companies.', 'community', NULLIF('https://www.altitudelab.org/', ''), NULLIF('info@altitudelab.org', ''), ARRAY[]::text[], ARRAY['life sciences and healthcare']::text[], ARRAY['validation', 'launched', 'traction']::text[], ARRAY['entrepreneurship-communities', 'relocate-a-business-to-utah']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2646', 'APEX Accelerator', 'The Utah APEX Accelerator, formerly known as the Procurement Technical Assistance Center (PTAC), assists Utah businesses in navigating and securing government contracts across federal, state, and local levels. The program offers services such as one-on-one counseling, training workshops, and access to bid opportunities, aiming to integrate businesses into the government industrial base and facilitate the transfer of innovative technologies to defense sectors. With regional managers located throughout the state, the APEX Accelerator provides personalized support to help businesses effectively compete in the government marketplace.', 'accelerator', NULLIF('https://business.utah.gov/apex/', ''), NULLIF('apex@utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2647', 'Small Business Development Center (SBDC)', 'The Utah Small Business Development Centers (SBDC) provide business owners and entrepreneurs with confidential consultations, training, and resources to help them start, grow, and transition their businesses. They offer free or low-cost training and support across various stages of business development, helping improve productivity, management, and success​.', 'investor', NULLIF('https://utahsbdc.org/', ''), NULLIF('mike.finnerty@usu.edu', ''), ARRAY['Any', 'Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['any', 'close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'multicultural', 'new-american', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'student', 'taxes-and-finance', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2648', 'Kem C. Gardner Policy Institute', 'The Kem C. Gardner Policy Institute, part of the University of Utah''s David Eccles School of Business, conducts economic, demographic, and public policy research to inform decision-making and promote Utah''s prosperity. Serving as a vital hub for policy leadership, the institute provides data-driven insights on topics such as the economy, public finance, demographics, and public policy. Their work supports state leaders in making informed decisions that benefit all Utahns.', 'community', NULLIF('https://gardner.utah.edu/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['other']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2649', 'StartUp State', 'The Utah Governor''s Office of Economic Opportunity''s Startup State Initiative celebrates, inspires, and empowers Utah entrepreneurs and those who support them. It consists of a statewide entrepreneurship brand and business resource portal being developed on this site. This collaborative initiative supports entrepreneurs throughout the lifecycle of their business and encourages them to start in Utah.', 'investor', NULLIF('https://startup.utah.gov/', ''), NULLIF('startup@utah.gov', ''), ARRAY['Any', 'Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['any', 'close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'multicultural', 'new-american', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'student', 'taxes-and-finance', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2650', 'Custom Fit Training', 'The Custom Fit Training program, administered by the Utah System of Higher Education (USHE), offers tailored training solutions to enhance employee productivity and support business growth across Utah. By partnering with local institutions, Custom Fit provides state-subsidized training in areas such as technical skills, safety certifications, leadership development, and more, with companies typically contributing at least 50% of the training costs. This initiative aims to strengthen Utah''s economic vitality by equipping the workforce with skills that meet specific industry needs.', 'service_provider', NULLIF('https://ushe.edu/custom-fit/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2651', 'A Bolder Way Forward', 'The "A Bolder Way Forward" initiative by Utah State University''s Utah Women & Leadership Project aims to make Utah a leading state for women-owned businesses in terms of growth and longevity. The Entrepreneurship spoke of this initiative focuses on eliminating barriers such as limited access to capital, mentors, affordable childcare, and awareness of business training and resources that hinder women from starting and sustaining successful businesses. By addressing these challenges, the program seeks to empower more Utah women to thrive as entrepreneurs, thereby enhancing the state''s economic vitality.', 'community', NULLIF('', ''), NULLIF('uwlp@usu.edu', ''), ARRAY['Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['other', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2652', 'SBA Thrive', 'The T.H.R.I.V.E. Emerging Leaders Reimagined program, offered by the U.S. Small Business Administration (SBA), is an intensive executive-level training series designed to accelerate the growth of high-potential small businesses. Over six months, participants engage in in-person coaching, self-paced instruction, mentoring, and classroom sessions, covering core business topics such as accounting, business strategy, marketing, and human resources. The program aims to equip small business executives with the skills and knowledge necessary to scale their operations and contribute to economic development.', 'service_provider', NULLIF('https://www.sba.gov/sba-learning-platform/thrive-emerging-leaders-reimagined', ''), NULLIF('sbathrivesupport@isomglobal.com', ''), ARRAY['Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth', 'multicultural', 'new-american', 'rural', 'student', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2653', 'Goldman Sachs 1000 Small businesses', '"Goldman Sachs 10,000 Small Businesses is an investment to help small businesses grow and create jobs by providing them with greater access to education, capital, and business support services. To date, more than 12,8000 business owners have graduated from the program across all 50 states, Washington D.C., and Puerto Rico.

Through the program, you will gain skills across topics such as financial statements negotiation, marketing, and employee management, and gain the tools to develop a customized business plan for growth – for free."', 'service_provider', NULLIF('https://10ksbapply.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['traction', 'scale']::text[], ARRAY['late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2654', 'Utah Innovation Center', 'The Utah Innovation Center, part of the Governor''s Office of Economic Opportunity, serves as a catalyst for technology innovation in Utah. It provides a funding roadmap for startups and emerging companies developing innovative technologies, offering services such as proposal review, training, and mentoring to assist businesses in securing non-dilutive funding through federal programs like the Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR).', 'incubator', NULLIF('https://business.utah.gov/innovation/', ''), NULLIF('innovationutah@utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'life sciences and healthcare', 'manufacturing', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2655', 'Utah Innovation Fund', 'The Utah Innovation Fund is a state-established venture capital fund dedicated to elevating Utah''s economy by commercializing technologies developed at the state''s higher education institutions. Its mission is to support and fund promising startups addressing global challenges, with a focus on early investments in innovative solutions and fostering deep tech leadership within Utah.', 'investor', NULLIF('https://www.utahinnovationfund.com/', ''), NULLIF('info@utahinnovationfund.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['funding']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2656', 'STRIVE', 'The Startup Training Resources to Inspire Veteran Entrepreneurship (STRIVE) program, offered by the Utah Veteran Business Resource Center (VBRC) in partnership with Syracuse University''s D''Aniello Institute for Veterans and Military Families (IVMF) and the National Association for Community College Entrepreneurship (NACCE), is a comprehensive six-week training initiative designed to assist veteran and military-connected entrepreneurs in developing early-stage business ideas. Participants receive in-depth training, mentorship, and access to a robust network of resources, both locally and nationally through the IVMF network, to support the successful launch and growth of their ventures.', 'mentor', NULLIF('https://utahvbrc.org/strive', ''), NULLIF('vbrc@slcc.edu', ''), ARRAY['Veteran']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation']::text[], ARRAY['entrepreneurship-communities', 'start-a-business', 'veteran']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2657', '1 Million Cups (Salt Lake)', 'The 1 Million Cups program in Salt Lake City fosters a supportive entrepreneurial community, connecting local entrepreneurs to resources and networking opportunities. Hosted weekly, the program encourages open dialogue about business challenges and solutions, promoting growth through collaboration and learning', 'mentor', NULLIF('https://1mcslc.com/', ''), NULLIF('saltlake@1millioncups.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation']::text[], ARRAY['entrepreneurship-communities', 'start-a-business']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2658', 'SCORE', 'SCORE Utah is a chapter of the national nonprofit organization dedicated to fostering vibrant small business communities through mentoring and education. Offering free, confidential business advice, SCORE Utah assists entrepreneurs in starting and growing their businesses by connecting them with experienced volunteer mentors from various industries. The chapter also provides workshops and webinars on essential business topics to equip small business owners with the knowledge and tools necessary for success.', 'investor', NULLIF('https://www.score.org/utah', ''), NULLIF('', ''), ARRAY['Any', 'Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['any', 'close-or-exit-a-business', 'funding', 'marketing-and-sales', 'multicultural', 'new-american', 'rural', 'student', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2659', '1 Million Cups (Orem)', '1 Million Cups is a national program that supports local entrepreneurs by providing a platform to present their ideas, share feedback, and connect with a community of like-minded individuals. The Orem chapter, hosted weekly at the UVU Business Resource Center, offers a welcoming space for networking, mentoring, and collaboration among startups, investors, and service providers in Utah County', 'mentor', NULLIF('https://www.1millioncups.com/s/account/0014W00002AqQfKQAV/orem-ut', ''), NULLIF('provo@1millioncups.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation']::text[], ARRAY['entrepreneurship-communities', 'start-a-business']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2660', 'Suazo Business Center', 'The Suazo Business Center is a nonprofit dedicated to supporting Latino and underserved communities in Utah through entrepreneurial resources. It provides business consulting, training, and financial assistance to help minority entrepreneurs succeed and build wealth, aiming to foster self-reliance and break cycles of poverty.', 'investor', NULLIF('https://suazocenter.org/', ''), NULLIF('getintouch@suazocenter.org', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2661', 'Utah Hispanic Chamber of Commerce', 'The Utah Hispanic Chamber of Commerce empowers Hispanic entrepreneurs and businesses by providing resources, advocacy, and networking opportunities. It focuses on fostering economic growth, cultural inclusion, and community engagement across Utah. Through education, mentorship, and support, the Chamber helps members thrive in a competitive business environment.', 'investor', NULLIF('https://utahhcc.com/', ''), NULLIF('info@utahhcc.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2662', 'Utah Black Chamber', 'The Utah Black Chamber supports the economic and professional development of Utah''s Black community through advocacy, education, and enterprise. The organization connects underrepresented businesses with resources to foster growth and sustainability. It hosts events like the Black Business Expo and Juneteenth celebrations to promote entrepreneurship and cultural enrichment while advocating for inclusive policies and equitable workplace practices​.', 'investor', NULLIF('https://www.utahblackchamber.com/', ''), NULLIF('info@utahblackchamber.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2663', 'Utah LGBTQ+ Chamber of Commerce', 'The Utah LGBTQ+ Chamber of Commerce supports LGBTQ+ and allied businesses by fostering an inclusive business community across the state. Founded in 2012 and expanded in 2019 to reflect greater inclusivity, it connects businesses, nonprofits, and government entities to promote equity, diversity, and inclusion. The Chamber offers networking opportunities, business development programs, and advocacy at various levels, while also assisting members with certifications, marketing, and growth initiatives.', 'investor', NULLIF('https://www.utahlgbtqchamber.org/', ''), NULLIF('boardofdirectors@utahlgbtqchamber.org', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2664', 'Women''s Business Center of Utah', 'The Women''s Business Center of Utah (WBCUtah) supports women entrepreneurs in the state through free advising, training, and resources. They offer a range of services, including workshops, mentorship, and online courses, aimed at helping women start, grow, and scale their businesses.', 'investor', NULLIF('https://wbcutah.org/', ''), NULLIF('info@wbcutah.org', ''), ARRAY['Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'start-a-business', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2665', 'Wasatch Women''s Business Alliance', 'The Wasatch Women''s Business Alliance (WWBA) is a nonprofit organization in Wasatch County, Utah, dedicated to supporting women-owned and operated businesses. It fosters growth through networking events, mentorship programs, and collaborative opportunities, enabling members to share experiences and resources. Regular meetings, such as the monthly networking sessions at the UVU Wasatch Campus, provide platforms for professional development and community engagement.', 'investor', NULLIF('https://thewwba.org/', ''), NULLIF('wasatchwomensbusinessalliance@gmail.com', ''), ARRAY['Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'start-a-business', 'women']::text[], ARRAY['Wasatch']::text[]),
    ('2666', 'Utah Native American Chamber of Commerce', 'The Utah Native American Chamber of Commerce, based in Salt Lake City, is dedicated to empowering Native American entrepreneurs and fostering the prosperity of Indigenous businesses across Utah. As a non-profit organization, it provides a platform for Native American entrepreneurs to showcase their businesses, connect with corporations, and serve as a liaison on tribal economic development issues. The Chamber offers resources, training, and networking opportunities tailored to the unique needs of Native American business owners, welcoming both Native and non-Native entrepreneurs to join in this collective journey of empowerment and collaboration.', 'investor', NULLIF('https://www.utncoc.com/', ''), NULLIF('info@utncoc.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Salt Lake']::text[]),
    ('2667', 'Bear Lake Regional Commission', 'The Bear Lake Regional Commission focuses on managing growth, preserving natural resources, and fostering collaboration between Idaho and Utah''s Bear Lake counties. It works to address environmental, economic, and recreational challenges in the region, ensuring sustainable development while enhancing the area''s natural beauty and accessibility.', 'investor', NULLIF('http://www.bearlakeregionalcommission.org/', ''), NULLIF('cjensen@cut.net', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'life sciences and healthcare']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Rich']::text[]),
    ('2668', 'Bear River Association of Governments', 'The Bear River Association of Governments (BRAG) supports local community and economic development by offering technical assistance to cities, towns, and counties in northern Utah. It helps with planning, strategic growth, housing, transportation, and securing funding for vital infrastructure projects to promote regional development and economic success​.', 'investor', NULLIF('https://brag.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Box Elder', 'Cache', 'Rich']::text[]),
    ('2669', 'Brigham City Economic Development', 'Brigham City''s Economic Development Department is dedicated to enhancing the city''s quality of life by fostering a vibrant business environment. The department offers support to businesses through streamlined application processes, tax increment financing via the Redevelopment Agency, and façade grant programs aimed at revitalizing the historic downtown district. Additionally, Brigham City provides well-developed infrastructure and is strategically located with access to major interstates and rail services, facilitating efficient transportation and logistics for businesses.', 'investor', NULLIF('https://www.bcutah.gov/page/economic-development/', ''), NULLIF('plarsen@bcutah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Box Elder']::text[]),
    ('2670', 'Logan City Economic Development', 'Logan City’s Economic Development Office fosters a business-friendly environment by supporting entrepreneurship, facilitating new business growth, and enhancing infrastructure for long-term success. The city provides resources such as business licensing, site selection tools, and economic data to assist businesses in thriving within Cache Valley.', 'investor', NULLIF('https://www.loganutah.gov/government/mayor_s_office/economic_development/index.php', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Cache']::text[]),
    ('2671', 'Bear Lake Valley Chamber of Commerce', 'The Bear Lake Valley Chamber of Commerce supports local businesses and fosters economic growth in the Bear Lake area. It provides resources, networking opportunities, and promotional efforts to help businesses thrive while enhancing the community''s appeal to residents and visitors. Through its initiatives, the Chamber strengthens the local economy and encourages collaboration among businesses.', 'investor', NULLIF('https://bearlakechamber.com/', ''), NULLIF('director@bearlakechamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Rich']::text[]),
    ('2672', 'Cache Valley Chamber of Commerce', 'The Cache Valley Chamber of Commerce promotes economic growth and community development in the Cache Valley region. It offers resources, advocacy, and networking opportunities to support businesses of all sizes. Through events and initiatives, the Chamber fosters collaboration and strengthens the local economy.', 'investor', NULLIF('https://cachechamber.com/', ''), NULLIF('info@cachechamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Cache']::text[]),
    ('2673', 'Box Elder Chamber of Commerce', 'The Box Elder Chamber of Commerce supports local businesses and promotes economic development throughout Box Elder County. It provides resources, networking opportunities, and community events to help businesses grow and connect. By fostering collaboration and advocating for its members, the Chamber strengthens the local economy and enhances community prosperity.', 'investor', NULLIF('https://www.boxelderchamber.com/', ''), NULLIF('monica@boxelderchamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Box Elder']::text[]),
    ('2674', 'Rural Utah Chamber Coalition', 'The Rural Utah Chamber Coalition is a partnership composed of chamber executives and board members, elected leaders, and government liaisons. Their goals are to discuss issues affecting and advocate for rural chambers and communities, provide strategic programming to further meaningful economic development, support rural innovation, and create prosperity for the people of rural Utah."', 'investor', NULLIF('https://www.ruralutahcc.org/', ''), NULLIF('info@ruralutahcc.org', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2675', 'Utah Pacific Islander Chamber of Commerce', 'The Utah Pacific Islander Chamber of Commerce (UPIC) is dedicated to empowering Pacific Islander entrepreneurs and businesses by providing resources, training, and networking opportunities. UPIC offers various programs, including mentorship, grants, culturally relevant education, and support for transitioning businesses from smaller operations to larger-scale establishments. Through events like the Pacific Islander Business Summit and partnerships with local organizations, UPIC fosters economic growth and strengthens community connections while promoting civic engagement and innovation​.', 'investor', NULLIF('https://www.upichamber.org/', ''), NULLIF('admin@upichamber.org', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'multicultural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2676', 'Salt Lake Chamber', 'The Salt Lake Chamber is Utah''s largest and longest-standing business association, representing approximately 7,700 businesses and nearly 500,000 jobs across all 29 counties. The Chamber serves as the voice of business, supporting member success and championing community prosperity through advocacy, networking opportunities, and various programs aimed at fostering economic growth and addressing key policy issues.', 'investor', NULLIF('https://slchamber.com/', ''), NULLIF('info@slchamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Salt Lake']::text[]),
    ('2677', 'Hurricane Valley Chamber of Commerce', 'The Hurricane Valley Chamber of Commerce serves as a vital resource for local businesses in Hurricane, Utah. It supports the community through networking opportunities, educational events, and business promotion activities, such as ribbon-cutting ceremonies and the annual Small Business Expo. The Chamber''s mission focuses on fostering economic growth, enhancing collaboration between businesses and civic leaders, and empowering small enterprises to thrive in a competitive environment​', 'investor', NULLIF('https://hvchamber.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Washington']::text[]),
    ('2679', 'Federal Economic Development Administration', 'The U.S. Economic Development Administration (EDA) is a federal agency within the Department of Commerce dedicated to promoting innovation and competitiveness to prepare American regions for growth and success in the global economy. It offers a variety of programs and funding opportunities, including grants for infrastructure development, technical assistance, and disaster recovery, aiming to support sustainable job growth and build resilient regional economies. By collaborating with local partners, the EDA focuses on initiatives that advance new ideas and creative approaches to address rapidly evolving economic conditions.', 'community', NULLIF('https://www.eda.gov/', ''), NULLIF('', ''), ARRAY['Rural']::text[], ARRAY['agriculture']::text[], ARRAY['validation']::text[], ARRAY['other', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2680', 'Utah Governor''s Office of Economic Opportunity', 'The Utah Governor''s Office of Economic Opportunity (Go Utah) fosters economic growth by supporting entrepreneurs, recruiting businesses, and implementing strategic development plans statewide. Under the leadership of Executive Director Ryan Starks, the office offers various programs, including business services, financial incentives, and the Utah Broadband Center, to enhance the state''s economic vitality. Go Utah collaborates with industries, communities, and nonprofits to ensure economic opportunities are accessible to all Utahns.', 'government', NULLIF('https://business.utah.gov/', ''), NULLIF('business@utah.gov', ''), ARRAY['Multicultural', 'New American', 'Rural', 'Student', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding', 'international-trade', 'late-stage-growth', 'marketing-and-sales', 'multicultural', 'new-american', 'other', 'relocate-a-business-to-utah', 'rural', 'start-a-business', 'student', 'taxes-and-finance', 'veteran', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2681', 'EDCUtah - Economic Development Corporation of Utah', 'EDCUtah provides businesses with the resources they need to relocate or expand their operations in Utah. We specialize in corporate recruitment and expansion projects, economic research, community strategy, and site selector engagement. As Utah’s only statewide economic development organization with a public-private partnership model, EDCUtah can connect growing companies to local experts in finance, law, talent recruitment, real estate, construction, utilities, and more.', 'investor', NULLIF('https://www.edcutah.org/', ''), NULLIF('connect@edcutah.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2682', 'Utah Center for Rural Development', 'The Center for Rural Development, part of Utah''s Governor''s Office of Economic Opportunity, collaborates with the state''s rural counties, communities, and businesses to provide economic development resources. It administers programs such as the Rural Communities Opportunity Grant (RCOG), which supports unique economic development projects, and the Rural Employment Development Incentive (REDI), offering grants to businesses creating high-paying jobs in rural areas. Additionally, the center manages initiatives like the Enterprise Zone Tax Credits and the Rural Economic Development Tax Increment Financing (REDTIF) to promote business growth and infrastructure development in Utah''s rural regions.', 'service_provider', NULLIF('', ''), NULLIF('business@utah.gov', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['entrepreneurship-communities', 'late-stage-growth', 'other', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2683', 'St George Downtown Farmers Market', 'The Downtown Farmers Market in St. George, Utah, is a year-round community event held at Vernon Worthen Park. It features over 60 vendors offering local produce, meats, artisanal products, and live entertainment every Saturday, fostering a vibrant, inclusive space for residents to connect and support local businesses', 'service_provider', NULLIF('https://downtownfarmerstg.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'hospitality and food services']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['entrepreneurship-communities', 'late-stage-growth', 'other']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2684', 'Utah Farmers Market Network', 'The Utah Farmers Market Network (UFMN) is a collaborative organization that supports and connects farmers markets across Utah, aiming to enhance local food systems and community engagement. It provides resources such as the Farmers Market Manager Handbook, guidance on SNAP & Double Up Food Bucks programs, and initiatives to create welcoming markets, all designed to assist market managers and vendors in operating successful and inclusive markets. UFMN also maintains a directory of farmers markets throughout the state, helping consumers locate markets and access fresh, locally produced goods.', 'service_provider', NULLIF('https://www.utahfarmersmarketnetwork.org/', ''), NULLIF('info@utahfarmersmarketnetwork.org', ''), ARRAY[]::text[], ARRAY['agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'hospitality and food services']::text[], ARRAY['validation', 'traction', 'scale']::text[], ARRAY['entrepreneurship-communities', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2685', 'Morgan County Economic Development', 'The Morgan County Economic Development Corporation fosters growth and development within Morgan County by supporting local businesses and attracting new opportunities. It offers resources, strategic planning, and community partnerships to enhance the area''s economic vitality. Through its efforts, the organization strengthens the local economy and promotes Morgan County as a thriving place to live and work.', 'investor', NULLIF('https://www.morgancountyinfo.com/', ''), NULLIF('mcedc@morgancountyinfo.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2686', 'Davis County Economic Development', 'The Davis County Community and Economic Development Department drives economic growth by supporting businesses, fostering community development, and enhancing the region’s quality of life. It provides resources for business expansion, workforce development, and strategic planning to strengthen the local economy. Through its initiatives, the department promotes Davis County as a vibrant hub for business and community opportunities.', 'investor', NULLIF('https://www.daviscountyutah.gov/ced', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2687', 'Weber County Economic Development', 'The Weber Economic Development Partnership (EDP) focuses on fostering economic growth and development in Weber County by supporting businesses and attracting new investments. It offers resources, strategic planning, and workforce development programs to strengthen the local economy. Through collaboration and innovation, Weber EDP promotes the county as a dynamic location for businesses and residents.', 'investor', NULLIF('https://webercountyutah.gov/weberedp/new/index.html', ''), NULLIF('srussell@webercountyutah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2688', 'Northern Utah Economic Alliance', 'The Northern Utah Economic Alliance (NUEA) promotes economic growth and development in Davis and Weber counties by attracting businesses, supporting expansion, and creating job opportunities. It collaborates with local governments, businesses, and stakeholders to strengthen the region’s economy and enhance its competitive advantage. Through its efforts, NUEA fosters innovation and sustainable growth to benefit Northern Utah communities.', 'investor', NULLIF('https://nuea.org/', ''), NULLIF('chris@nuea.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2689', 'Six County Association of Governments', 'Region 6 Economic Development focuses on fostering economic growth in Morgan, Tooele, and Weber Counties by supporting local businesses, attracting new investments, and enhancing community development. It provides resources, strategic partnerships, and workforce initiatives to strengthen the region''s economy. Through collaboration and innovation, Region 6 aims to create sustainable opportunities for businesses and residents alike.', 'investor', NULLIF('https://r6.utah.gov/', ''), NULLIF('abbyivory@sixcounty.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2690', 'Uinta Basin Association of Governments', 'The Uintah Basin Association of Governments (UBAOG) serves Daggett, Duchesne, and Uintah counties in Utah, offering programs to enhance economic and social development. Their services include housing rehabilitation, community services, and the H.E.A.T. program, which provides utility assistance to eligible households. UBAOG also operates food pantries and offers emergency shelter options for residents in need.', 'investor', NULLIF('https://www.ubaog.org/', ''), NULLIF('laurieb@ubaog.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Daggett', 'Duchesne', 'Uintah']::text[]),
    ('2691', 'Wasatch Front Regional Council', 'The Wasatch Front Regional Council (WFRC) is an association of governments comprising elected officials from Box Elder, Davis, Morgan, Salt Lake, Tooele, and Weber counties in Utah. As the designated Metropolitan Planning Organization (MPO) for the Salt Lake City-West Valley City and Ogden-Layton urbanized areas, WFRC coordinates transportation planning, regional visioning, and community and economic development efforts. Their mission is to build consensus and enhance quality of life by developing and implementing visions and plans for a well-functioning multi-modal transportation system, livable communities, a strong economy, and a healthy environment.', 'investor', NULLIF('https://wfrc.org/contact/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis', 'Morgan', 'Salt Lake', 'Tooele', 'Weber']::text[]),
    ('2692', 'Southeastern Association of Local Governments', 'The Southeastern Utah Association of Local Governments (SEUALG) serves Carbon, Emery, Grand, and San Juan counties, focusing on economic development, housing, and community services. Their programs include housing assistance, transportation planning, food security initiatives, community gardens, weatherization services, and income tax assistance. SEUALG also offers aging services, poverty initiatives, and business finance support to enhance the quality of life for residents in southeastern Utah.', 'investor', NULLIF('https://serda.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2693', 'Mountainland Association of Governments', 'The Mountainland Association of Governments (MAG) serves Summit, Utah, and Wasatch counties, focusing on regional collaboration, access to funding and services, and advocating for local issues. MAG''s programs include Aging & Family Services, Community & Economic Development, and Planning for Growth, aiming to empower communities to achieve their vision.', 'investor', NULLIF('https://mountainland.org/', ''), NULLIF('mcarroll@magutah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2694', 'Bear River Association of Governments', 'The Bear River Association of Governments (BRAG) serves Box Elder, Cache, and Rich counties in Utah, offering services for low-income households, seniors, and individuals with disabilities. BRAG also provides community and economic development assistance to local governments, aiming to enhance regional cooperation and development.', 'investor', NULLIF('https://brag.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Box Elder', 'Cache', 'Rich']::text[]),
    ('2695', 'Five County Association of Governments', 'The Five County Association of Governments (FCAOG) is a voluntary association serving the southwestern Utah counties of Beaver, Garfield, Iron, Kane, and Washington. Established in 1972, FCAOG provides assistance in community and economic development, transportation planning, aging programs, and human services to enhance regional collaboration and address area-wide concerns. Their main office is located in St. George, with a satellite office in Cedar City.', 'investor', NULLIF('http://www.fivecounty.utah.gov/', ''), NULLIF('info@fivecounty.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2696', 'Vernal Downtown Alliance', 'The Vernal Downtown Alliance is a nonprofit organization dedicated to revitalizing and promoting Vernal''s historic downtown area. It provides networking opportunities for business owners, connects them to essential resources, and collaborates with local agencies to create a prosperous and welcoming downtown environment. Guided by the Main Street Approach, the Alliance focuses on economic vitality, design, promotion, and organization to strengthen the community''s core.', 'investor', NULLIF('https://www.vernaldowntown.org/', ''), NULLIF('vernaldt@gmail.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Daggett', 'Duchesne', 'Uintah']::text[]),
    ('2697', 'Uintah County Economic Development', 'The Uintah County Economic Development Department in Utah fosters sustainable economic growth by supporting local businesses, attracting new enterprises, and enhancing residents'' quality of life. It offers resources such as grants, business incentives, and strategic planning to promote a vibrant economy. The department collaborates with public and private partners to provide programs and services that encourage entrepreneurship and job creation within the region.', 'investor', NULLIF('https://business.uintah.gov/', ''), NULLIF('tcampbell@uintah.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Daggett', 'Duchesne', 'Uintah']::text[]),
    ('2698', 'Utah Alliance for Economic Development', 'The Utah Alliance for Economic Development is a statewide organization made up of economic development professionals from various sectors, including government, utilities, real estate, and private firms. It focuses on supporting Utah’s economy by offering professional development, networking opportunities, and advocating for policies that strengthen local communities. The Alliance also hosts quarterly meetings in different cities to encourage collaboration and knowledge sharing among its members.', 'investor', NULLIF('https://www.utahalliance.com/', ''), NULLIF('utahalliance@utahalliance.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2699', 'Utah Inland Port Authority', 'The Utah Inland Port Authority (UIPA) is a state organization leading and implementing logistics solutions to support Utah''s economic growth and environmental protection. It focuses on creating generational regional economic growth, establishing Utah as a leading global trade logistics hub, and advancing sustainable and smart supply chains. UIPA collaborates with communities across the state to set a foundation for positive generational impact, ensuring a brighter future for all Utah residents.', 'investor', NULLIF('https://inlandportauthority.utah.gov/', ''), NULLIF('info@inlandportauthority.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2700', 'Utah Regional Growth Association', 'The Utah Regional Growth Association assists Utah communities in creating and deploying strategies that lead to economic growth and diversification.', 'investor', NULLIF('https://www.utrga.org/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2701', 'Grand County Economic Development', 'The Grand County Economic Development Department in Utah focuses on diversifying the local economy by supporting non-tourism-based activities that promote sustainability, livability, and resilience. They offer resources and assistance to businesses and organizations aiming to establish or expand operations within the county, fostering a diverse mix of industries to withstand economic fluctuations. The department also engages with the community to prioritize the allocation of funds for economic diversification projects, ensuring that development aligns with residents'' needs and the county''s strategic goals.', 'investor', NULLIF('https://www.co.grand.co.us/1056/Economic-Development', ''), NULLIF('bfredregill@grandcountyutah.net', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2702', 'Carbon County Economic Development', 'The Carbon County Economic Development Department in Utah is dedicated to enhancing the local economy by fostering a business-friendly environment for both existing and new enterprises. They engage in collaborative efforts to promote regional alignment, business development and expansion, workforce development, affordable housing, and tourism. The department also administers programs like the Rural County Grant to support business recruitment, infrastructure improvements, and workforce training.', 'investor', NULLIF('https://www.carbon.utah.gov/department/economic-development/', ''), NULLIF('cced@carbon.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2703', 'Southeastern Utah Association of Local Governments - Economic Development', 'The Southeastern Utah Association of Local Governments (SEUALG) serves Carbon, Emery, Grand, and San Juan counties, focusing on economic development, community planning, and human services to enhance regional prosperity. Through initiatives like the Comprehensive Economic Development Strategy (CEDS) and the Revolving Loan Fund (RLF), SEUALG supports job creation, infrastructure improvements, and business growth. Additionally, the organization offers programs in housing rehabilitation, transportation planning, food security, and weatherization to improve residents'' quality of life.', 'investor', NULLIF('https://seualg.utah.gov/index.php/economic-development/', ''), NULLIF('ggamber@seualg.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2705', 'St George Area Chamber of Commerce', 'The St. George Area Chamber of Commerce serves as a vital resource for businesses in the region, offering advocacy, networking, and training opportunities to its members. With a focus on fostering economic growth, the chamber supports over 1,000 businesses and nonprofits, aiming to create a thriving local economy and prosperous community. Through collaborations with government leaders and economic partners, it helps reduce barriers to business success and encourages innovation and free-market competition.', 'investor', NULLIF('https://stgeorgechamber.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Washington']::text[]),
    ('2706', 'UZONA - Hildale Chamber of Commerce', 'The UZONA Chamber of Commerce supports the economic development and community growth of Southern Utah and Northern Arizona, spanning areas like Apple Valley, Hildale, and the Kaibab Paiute Reservation. It fosters local businesses through networking events, visitor guides, and community initiatives, highlighting regional attractions and amenities. The chamber actively engages in creating opportunities for collaboration and promoting the area''s unique culture and commerce.', 'investor', NULLIF('https://www.uzonachamber.org/', ''), NULLIF('admin@uzonachamber.org', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'multicultural']::text[], ARRAY['Kane', 'Washington']::text[]),
    ('2707', 'Washington Area Chamber of Commerce', 'The Washington Area Chamber of Commerce is dedicated to supporting and growing businesses in the greater Washington Area and connecting businesses with the Community and Government. They strive to foster a successful economy by promoting the area as an attractive travel and shopping destination.', 'investor', NULLIF('https://washingtonutchamber.com/', ''), NULLIF('hello@washareachamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Washington']::text[]),
    ('2708', 'BIG Chamber (Beaver, Iron, Garfield)', 'The BIG Chamber of Commerce supports businesses and communities in Beaver, Iron, and Garfield Counties, Utah. It provides members with resources like networking opportunities, advocacy, training, and marketing tools to foster business growth and community prosperity. By promoting collaboration and regional economic development, the chamber aims to create a healthy and thriving environment for local businesses.', 'investor', NULLIF('https://www.bigchamber.org/', ''), NULLIF('office@bigchamber.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Garfield', 'Iron']::text[]),
    ('2709', 'Cedar City Area Chamber of Commerce', 'The Cedar City Chamber of Commerce serves as a resource for businesses and the community in Cedar City, Utah, providing support for economic development, business networking, and local events. It offers initiatives such as luncheons, expos, and an awards gala to foster engagement and celebrate regional success. The chamber also acts as a hub for information, helping businesses and residents access services and connect with opportunities in Iron County and beyond', 'investor', NULLIF('https://www.cedarcitychamber.org/', ''), NULLIF('mrc@cedarcitychamber.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Iron']::text[]),
    ('2710', 'Heber Valley Chamber of Commerce', 'The Heber Valley Chamber of Commerce is dedicated to uniting, connecting, and promoting the diverse businesses and organizations that enrich Wasatch County. It provides members with opportunities for strategic networking, tailored promotional services, and impactful advocacy to foster economic growth. The Chamber actively supports a thriving business ecosystem through exclusive programs and benefits while encouraging collaboration to build a prosperous future for the community.', 'investor', NULLIF('https://www.gohebervalley.com/chamber/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Wasatch']::text[]),
    ('2711', 'Park City Chamber of Commerce', 'The Park City Chamber of Commerce & Visitors Bureau embodies the spirit of "Mountainkind," a philosophy that highlights the stewardship and community values cherished in the mountains of Park City. It promotes a culture of neighborly support, trail maintenance, volunteerism, and hospitality toward visitors, reflecting the collaborative ethos of its over 1,000 local business partners. The Chamber provides resources such as business services, employee benefits, networking opportunities, and policy advocacy, while encouraging engagement in community life through outdoor activities, volunteering, and cultural appreciation.', 'investor', NULLIF('https://www.parkcitychamber.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Summit']::text[]),
    ('2712', 'Moab Chamber of Commerce', 'The Moab Area Chamber of Commerce serves as a hub for business support and community development in the Moab region. It offers resources such as business coaching, training programs, networking opportunities, and advocacy to help local businesses thrive while fostering a vibrant community environment.', 'investor', NULLIF('https://moabchamber.com/', ''), NULLIF('info@moabchamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Grand']::text[]),
    ('2713', 'San Juan County Chamber of Commerce', 'The San Juan County Chamber of Commerce supports businesses in Southeastern Utah through advocacy, networking, and community-focused initiatives. It provides resources to local enterprises, hosts events like the "Best of San Juan Awards," and promotes regional growth by connecting businesses and residents to opportunities for collaboration and development​', 'investor', NULLIF('https://sanjuancountychamber.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['San Juan']::text[]),
    ('2714', 'Carbon County Chamber of Commerce', 'The Carbon County Chamber of Commerce is dedicated to fostering economic growth and community development in Carbon County, Utah. It serves businesses of all sizes through initiatives like networking events, promotional opportunities, and advocacy at the local, state, and federal levels, working closely with local cities and the county’s economic development department. Members benefit from resources such as a business directory, training programs, and events like luncheons and award ceremonies, all aimed at enhancing business visibility and community engagement.', 'investor', NULLIF('https://www.carboncountychamber.net/', ''), NULLIF('ccc@carboncountychamber.net', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon']::text[]),
    ('2715', 'Richfield Chamber of Commerce', 'The Richfield Area Chamber of Commerce serves as a central hub for businesses in Sevier County, Utah, focusing on fostering a thriving local economy through networking, advocacy, and community events. The Chamber provides resources for business growth, hosts events like the annual dinner and holiday parades, and recognizes local excellence.', 'investor', NULLIF('https://richfieldareachamber.com/', ''), NULLIF('richfieldut.areachamber@outlook.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Sevier']::text[]),
    ('2716', 'Sanpete Chamber of Commerce', 'The Sanpete County Chamber of Commerce supports local businesses by offering networking opportunities, advocacy, and resources to help them thrive in the community. It focuses on enhancing visibility, fostering community connections, and providing educational events and industry insights to empower businesses and contribute to the region''s economic growth​.', 'investor', NULLIF('https://sanpetechamberofcommerce.org/', ''), NULLIF('info@sanpetechamberofcommerce.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Sanpete']::text[]),
    ('2717', 'Delta Area Chamber of Commerce', 'The Delta Area Chamber of Commerce (DACC) is dedicated to promoting the economic, civic, and cultural prosperity of Delta, Utah, and its surrounding areas. It offers a variety of services, such as business marketing assistance, networking opportunities, and community-focused events like the Snow Goose Festival, fostering a vibrant and collaborative environment for local businesses and residents to thrive.', 'investor', NULLIF('https://www.deltautahchamber.com/', ''), NULLIF('deltautahchamber@gmail.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Millard']::text[]),
    ('2718', 'Salina Chamber', 'The Salina Area Chamber of Commerce is a vital nonprofit organization representing over 1,200 local businesses and professionals working together to enhance the community''s economy and quality of life. With a mission to advocate for its members'' prosperity, the Chamber plays a key role in supporting economic development, promoting local businesses, and fostering community engagement.', 'investor', NULLIF('https://www.salina.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Sevier']::text[]),
    ('2719', 'Greater Nephi Chamber of Commerce', 'The Greater Nephi Chamber of Commerce serves to unite local businesses in the community for the purposes of innovation, advocacy, and education. It focuses on promoting economic growth, supporting small businesses, and fostering collaboration between businesses, community leaders, and educational institutions.', 'investor', NULLIF('https://www.nephichamber.org/', ''), NULLIF('nephichamber@gmail.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Juab']::text[]),
    ('2720', 'Flaming Gorge Chamber of Commerce', 'The Flaming Gorge Chamber of Commerce promotes tourism and economic development in Daggett County, Utah. It serves as the regional marketing organization, sponsoring and executing various year-round events to enhance community growth and address local business issues. Membership benefits include business listings on their website and in the Flaming Gorge Adventure Guide, increasing visibility to thousands of potential visitors.', 'investor', NULLIF('https://www.flaminggorgecountry.com/Chamber-of-Commerce/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Daggett']::text[]),
    ('2721', 'Vernal Area Chamber of Commerce', 'The Vernal Area Chamber of Commerce serves as a central hub for businesses in Vernal, Utah, offering a variety of resources and networking opportunities. Through membership, businesses gain access to promotional services, advocacy, and community engagement activities that contribute to a thriving local economy.', 'investor', NULLIF('https://www.vernalchamber.com/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Uintah']::text[]),
    ('2722', 'San Juan County Economic Development', 'The San Juan County Economic Development Department in Utah focuses on fostering economic growth by supporting local businesses, attracting new industries, and enhancing the quality of life for residents. They collaborate with various partners to provide resources, training, and programs aimed at business expansion, workforce development, and infrastructure improvement. The department also promotes the county''s abundant recreational opportunities and cultural heritage to boost tourism and community engagement.', 'investor', NULLIF('https://www.sjcutaheconomicdevelopment.com/', ''), NULLIF('thansen@sanjuancounty.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2723', 'Emery County Economic Development', 'The Emery County Economic Development Department in Utah offers various programs to support local businesses and attract new enterprises to the area. They assist companies in applying for Fast Track Grants, provide tax incentives to promote growth, and collaborate with the Small Business Development Center to offer one-on-one management consulting. Additionally, the department utilizes the Business Expansion and Retention (BEAR) program to analyze customer data, enabling strategic decisions that enhance economic, workforce, and community development on a company-by-company basis', 'investor', NULLIF('https://www.emerycountychamber.com/emery-economic-development.html', ''), NULLIF('jordanl@emery.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Carbon', 'Emery', 'Grand', 'San Juan']::text[]),
    ('2725', 'Davis Chamber of Commerce', 'Since its formation, the Davis Chamber of Commerce has continued to serve as a vital representative for the business community in Davis County. It acts as the collective voice and advocate for businesses of all sizes in the region, which is essential for ensuring the interests and concerns of local businesses are effectively communicated and addressed.', 'investor', NULLIF('https://davischamberofcommerce.com/', ''), NULLIF('info@davischamberofcommerce.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Davis']::text[]),
    ('2726', 'Ogden-Weber Chamber of Commerce', 'The Ogden-Weber Chamber of Commerce is a dynamic organization supporting businesses in Weber County through networking, professional development, and advocacy. Hosting over 100 events annually, including luncheons, workshops, and community celebrations, it provides a robust platform for local business growth and community engagement', 'investor', NULLIF('https://www.ogdenweberchamber.com/', ''), NULLIF('info@ogdenweberchamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Weber']::text[]),
    ('2727', 'Sevier County Economic Development', 'The Sevier County Economic Development Council (SCEDC) facilitates business growth and relocation in Sevier County, Tennessee, by connecting businesses with city planners and providing essential resources. They offer information on industrial parks, planning and permitting processes, and demographic data to assist businesses in making informed decisions. SCEDC also collaborates with educational institutions to support workforce development through programs like the Sevierville Hospitality Internship Program and S.E.V.I.E.R. Ready.', 'investor', NULLIF('https://scedc.com/', ''), NULLIF('allennewton@hotmail.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2728', 'Juab County Economic Development', 'Juab County, established in 1852, is located in western Utah with Nephi as its county seat. The county''s official website provides residents and visitors with information on government services, departments, and community resources, including property searches, tax payments, and public meeting agendas. The site also offers updates on county news, events, and access to various applications and permits.', 'investor', NULLIF('https://juabcounty.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2729', 'Morgan Chamber of Commerce', 'The Morgan Utah Chamber of Commerce is dedicated to supporting local businesses by providing resources, networking opportunities, and advocacy for growth and success. With a strong focus on community engagement and economic development, the Chamber encourages local partnerships and offers events such as the Hometown Christmas and Tree Festival, aimed at bringing people together while benefiting local families in need.', 'investor', NULLIF('https://www.morganutahchamber.org/', ''), NULLIF('info@morganutahchamber.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Morgan']::text[]),
    ('2730', 'R6 Regional Council', 'The R6 Regional Council, formerly known as the Six County Association of Governments, serves Juab, Millard, Piute, Sanpete, Sevier, and Wayne counties in Utah. It aims to improve local government coordination through programs in community development, economic planning, housing assistance, and aging services. The council facilitates regional collaboration to address shared challenges and promote sustainable growth.', 'investor', NULLIF('https://r6.utah.gov/', ''), NULLIF('abbyivory@r6.utah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Juab', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Wayne']::text[]),
    ('2731', 'Utah League of Cities & Towns (ULCT)', 'The Utah League of Cities and Towns (ULCT), established in 1907, is a non-partisan, inter-local government cooperative representing 248 municipalities across Utah. ULCT advocates for municipal interests at state and federal levels, providing information, training, and technical assistance to local officials on various municipal issues. The organization aims to strengthen the quality of local governance and administration throughout Utah''s cities and towns.', 'investor', NULLIF('https://www.ulct.org/', ''), NULLIF('info@ulct.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2732', 'Utah Association of Counties (UAC)', 'The Utah Association of Counties (UAC), established in 1924, is a voluntary, statewide organization representing all 29 counties in Utah. UAC provides services to county governments and officials, including training, legislative advocacy, and legal assistance, to enhance the quality of services for residents. The association serves as a unified voice for county governments, ensuring their interests are represented at both state and federal levels.', 'investor', NULLIF('https://www.uacnet.org/', ''), NULLIF('admin@uacnet.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2733', 'Five County Association of Governments', 'The Five County Association of Governments (FCAOG) serves Beaver, Garfield, Iron, Kane, and Washington counties in southwestern Utah, coordinating resources and programs to improve regional planning, community development, and public services. It offers a range of assistance, including housing programs, economic development initiatives, and social services, aiming to enhance self-sufficiency and address community needs effectively.', 'investor', NULLIF('http://www.fivecounty.utah.gov/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2734', 'Summit County Economic Development', 'The Summit County Economic Development Department in Utah supports local businesses and attracts new enterprises to enhance the county''s economic vitality. It offers resources for business expansion, workforce development, and community planning, aiming to create a sustainable and high-performance economy. The department collaborates with public and private partners to provide programs and services that foster entrepreneurship and job creation within the region.', 'investor', NULLIF('https://www.summitcountyutah.gov/609/Economic-Development', ''), NULLIF('jjones@summitcountyutah.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2735', 'Heber Valley Economic Development', 'Heber Valley''s Economic Development Office in Utah fosters sustainable growth by supporting local businesses, attracting new enterprises, and enhancing residents'' quality of life. The office provides resources such as economic incentives, strategic planning, and community engagement initiatives to promote a vibrant economy.', 'investor', NULLIF('https://www.gohebervalley.com/Economic-Development/', ''), NULLIF('info@gohebervalley.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2736', 'SoUtah Economic Alliance', 'The SoUtah Economic Alliance promotes economic development in Washington County, Utah, by highlighting the region''s business-friendly environment, diverse economy, and high quality of life. The alliance provides information on regional job growth, median household income, and population statistics to attract businesses and investors. Additionally, it organizes events like the "What''s Up Down South" Economic Summit to inform and engage the business community.', 'investor', NULLIF('https://soutah.org/', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Washington']::text[]),
    ('2737', 'Heber City Community Alliance for Main Street', 'The Community Alliance for Main Street (CAMS) is a grassroots volunteer organization dedicated to revitalizing and enhancing Heber City''s Main Street. CAMS focuses on advocacy, public art installations, and fundraising events to foster a vibrant downtown that reflects the community''s unique charm and history. By collaborating with local businesses, property owners, and residents, CAMS aims to transform Main Street into a bustling, pedestrian-friendly destination that serves as the economic and social hub of Heber City.', 'investor', NULLIF('https://hebercity-cams.org/', ''), NULLIF('info@hebervalleychamber.com', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Summit', 'Utah', 'Wasatch']::text[]),
    ('2738', 'Washington City Economic Development', 'Washington City''s Economic Development Division is focused on fostering business growth, supporting entrepreneurs, and promoting a vibrant local economy. The department provides resources for site selection, business incentives, and connections to community partners, making it a hub for business expansion in southern Utah.', 'investor', NULLIF('https://washingtoncity.org/development/economicdevelopment', ''), NULLIF('rhughes@washingtoncity.org', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Washington']::text[]),
    ('2739', 'St. George City Economic Development', 'The Economic Development Department of St. George, Utah, is focused on fostering growth through projects like Tech Ridge, a mixed-use development transforming the former airport site into a hub for tech companies, retail spaces, and recreation. With initiatives to diversify the economy, attract high-paying jobs, and improve community amenities, the city aims to establish itself as a competitive and vibrant center for innovation and lifestyle enhancement', 'investor', NULLIF('https://sgcityutah.gov/departments/economic_development/index.php', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2740', 'Iron County Economic Development', 'Cedar City’s Economic Development Office focuses on fostering business growth, attracting high-quality companies, and enhancing the region''s economic environment. It leverages the area''s strategic location, strong infrastructure, and collaborative community to support new and expanding businesses while promoting tourism and quality of life improvements​', 'investor', NULLIF('https://www.cedarcityut.gov/2357/Economic-Development', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth']::text[], ARRAY['Beaver', 'Garfield', 'Iron', 'Kane', 'Washington']::text[]),
    ('2748', 'Utah Digital Entertainment Network', 'The Utah Digital Entertainment Network (UDEN) is a nonprofit, voluntary trade group dedicated to uniting and promoting Utah''s digital entertainment industry, encompassing film, gaming, education, and technology sectors. Founded and operated by local industry professionals, UDEN aims to foster a collaborative community by connecting creators, facilitating networking opportunities, and serving as a collective voice to drive economic growth and innovation within the state''s digital entertainment landscape.', 'investor', NULLIF('https://utahden.org/', ''), NULLIF('info@utahden.org', ''), ARRAY[]::text[], ARRAY['arts and entertainment and recreation', 'other']::text[], ARRAY['idea', 'validation', 'mvp', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'other', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2801', 'Uintah Basin Economic Development District', 'The UBEDD actively seeks to build sustainable communities, which includes diversifying the economy and enhancing small businesses and entrepreneurship.', 'investor', NULLIF('https://www.ubaog.org/economic-development-district', ''), NULLIF('', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'fundraising', 'scale']::text[], ARRAY['close-or-exit-a-business', 'entrepreneurship-communities', 'funding']::text[], ARRAY['Daggett', 'Duchesne', 'Uintah']::text[]),
    ('2886', 'Utah Muslim Civic League (UMCL)', 'The Utah Muslim Civic League (UMCL) is a nonprofit organization dedicated to educating and empowering Utah''s Muslim community to engage in civic and charitable activities. UMCL represents over 60,000 Muslims from 120 nationalities in Utah, with an active voter base exceeding 15,000. Their initiatives include voter education, leadership development, advocacy, and community resource programs, aiming to amplify Muslim voices and foster inclusive civic participation.', 'investor', NULLIF('https://www.utahmcl.com/', ''), NULLIF('info@utahmcl.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2887', 'Utah Asian Chamber of Commerce (UACC)', 'The Utah Asian Chamber of Commerce (UACC) is a registered 501(c)(6) nonprofit organization dedicated to promoting the social and economic interests of Asian professionals and businesses in Utah. UACC offers its members access to exclusive events, business mentorship, and various resources aimed at fostering successful entrepreneurship and professional development. The Chamber organizes events such as the Annual Scholarship & Awards Gala and the Access Asia program to support local Asian communities and businesses.', 'investor', NULLIF('https://utahasianchamber.org/', ''), NULLIF('infouacc@gmail.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2891', 'Utah Chinese Association', 'The Utah Chinese Association (UCA) is a 501(c)(3) nonprofit organization established in 2016, dedicated to uniting Utah communities through cultural engagement, historical education, and social services. As the parent organization of the Chinese Folk Art Festival, Utah Chinese History Museum, and Utah Asian Alliance, UCA organizes events and programs that celebrate Chinese heritage and promote cultural exchange.', 'investor', NULLIF('https://www.utahchineseassociation.org/', ''), NULLIF('utahchinese2021@gmail.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2892', 'Pacific Island Chamber of Commerce (PICC)', 'The Pacific Island Chamber of Commerce (PICC), a program of Pacific Island Knowledge 2 Action Resources (PIK2AR), is dedicated to fostering economic growth and development within Utah''s Pacific Islander community. PICC serves as an educational and resource hub for business owners and entrepreneurs, offering culturally relevant business training, mentorship, and networking opportunities. With chapters in Salt Lake County and Utah County, PICC emphasizes mutual support and connection to help Pacific Islander businesses thrive.', 'investor', NULLIF('https://www.pik2ar.org/picc', ''), NULLIF('chamber@pik2ar.org', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2899', 'Utah Korean Chamber of Commerce', 'The Utah Korean Cultural Center (UKCC) is a nonprofit organization dedicated to promoting Korean culture and heritage within Utah. UKCC offers various programs and events, including language classes, cultural workshops, and traditional performances, to foster understanding and appreciation of Korean traditions. The center serves as a hub for cultural exchange, aiming to strengthen the Korean-American community and build connections with the broader public.', 'investor', NULLIF('https://www.utahkcc.org/', ''), NULLIF('utahkcc@gmail.com', ''), ARRAY['Multicultural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'launched', 'traction', 'fundraising']::text[], ARRAY['entrepreneurship-communities', 'funding', 'marketing-and-sales', 'multicultural', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('2909', '1MC Salt Lake', 'A Supportive Business & Startup Community in Salt Lake City

1MC Salt Lake is a weekly event for founders, entrepreneurs, and small business owners. The weekly event is an educational experience for both the audience and presenters.', 'investor', NULLIF('http://www.1mcslc.com', ''), NULLIF('Robert@1mcslc.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation', 'mvp', 'fundraising']::text[], ARRAY['any', 'entrepreneurship-communities', 'funding', 'other', 'start-a-business']::text[], ARRAY['Salt Lake']::text[]),
    ('3386', 'Startup Ignition Ventures', 'Startup Ignition Ventures is an Utah-based early stage pre-seed venture capital firm investing first checks into visionary startups with validated potential. The firm focuses on sectors such as technology, software, and SaaS.', 'investor', NULLIF('https://startupignition.com/ventures', ''), NULLIF('ventures@startupignition.com', ''), ARRAY['Any']::text[], ARRAY['software and information technology']::text[], ARRAY['mvp', 'fundraising']::text[], ARRAY['any', 'funding']::text[], ARRAY['Utah']::text[]),
    ('3519', 'LiaLaunch', 'LiaLaunch is a Utah-based strategic advisory and investment fund dedicated to championing women entrepreneurs by offering essential early-stage investment and unwavering support during the critical stages of business ideation, launch, and scale.', 'investor', NULLIF('https://www.lialaunch.com/', ''), NULLIF('contact@lialaunch.com', ''), ARRAY['Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation', 'mvp', 'traction', 'fundraising', 'scale']::text[], ARRAY['entrepreneurship-communities', 'funding', 'late-stage-growth', 'women']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3623', 'Coworking Space in Salt Lake City - Offices.net', 'Because they come in several levels, coworking memberships are easily customizable to meet your specific needs. One of the main attractions of coworking is the exclusive amenities, which turn shared workspaces into experiences in and of themselves. The emphasis is always on enhancing members'' productivity and well-being. Offices.net offers dedicated desks, hot desk day passes, shared office space, creative workspaces, and business center lounges throughout Utah.', 'coworking', NULLIF('https://offices.net/ut/salt-lake-city/coworking/', ''), NULLIF('info@offices.net', ''), ARRAY['Any', 'Multicultural', 'New American', 'Rural', 'Veteran', 'Women']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['any', 'entrepreneurship-communities', 'multicultural', 'new-american', 'rural', 'veteran', 'women']::text[], ARRAY['Salt Lake']::text[]),
    ('3624', 'Salt Lake City Office Space for Rent', 'Offices.co offers fully furnished executive suites, professionally equipped office space, and cost-effective shared workspaces and corporate real estate in 143 cities across the USA, including in and around Salt Lake City. The available office space for rent in Utah includes a wide range of essential services, so setting up a business in the Beehive State is faster and easier than ever.', 'mentor', NULLIF('https://offices.co/usa/salt-lake-city/', ''), NULLIF('info@offices.co', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation']::text[], ARRAY['any', 'entrepreneurship-communities', 'start-a-business']::text[], ARRAY['Utah']::text[]),
    ('3665', 'FutureReady Utah', 'Personalized Support from a Targeted Outreach Coordinator (TOC) in your county!
Our TOCs offer no-cost, hands-on support for community and business leaders. Whether you need help addressing a specific challenge or are looking for ongoing guidance, your TOC can assist with hiring and retention strategies, training connections, and workplace improvements. This support can be a one-time consultation or part of a long-term partnership—whatever fits your goals.', 'community', NULLIF('http://futurereadyutah.org', ''), NULLIF('futureready@suu.edu', ''), ARRAY['Rural']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['other', 'rural']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Piute', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3666', 'U.S. Commercial Service', 'The U.S. Commercial Service is the export promotion arm of the U.S. Department of Commerce.  Their mission is to help companies expand internationally by understanding the export process, selecting export markets, finding and vetting foreign partners, advocating on bids for foreign tenders, and resolving trade barriers. Whether you are looking to make your first export sale or expand to additional markets, we offer the experience and services you need to grow international sales of your U.S. made products and services.', 'community', NULLIF('https://www.trade.gov/utah-salt-lake-city', ''), NULLIF('Daniel.Bruner@trade.gov', ''), ARRAY['Any']::text[], ARRAY['other']::text[], ARRAY['launched', 'traction']::text[], ARRAY['any', 'international-trade']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3667', 'STOPfakes.gov', 'STOPfakes.gov is a one-stop shop for U.S. government tools and resources on intellectual property rights (IPR). The federal agencies behind STOPfakes.gov have developed a number of resources to educate and assist businesses, particularly small and medium-sized enterprises (SMEs), as well as consumers, government officials, and the general public.', 'community', NULLIF('https://www.stopfakes.gov/welcome', ''), NULLIF('stopfakes@trade.gov', ''), ARRAY[]::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['launched', 'traction']::text[], ARRAY['international-trade']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3683', 'Ai Seminar for Small Businesses &amp; Non-Profits', 'We''re offering a free seminar for small businesses & non-profits to learn how to formulate an Ai strategy that can be applied to each department. It will be held on Tues., June 24th in downtown Salt Lake. We are partnering with a local non-profit to make it an educational and applicable resource for smaller organizations. (Please email me if this event qualifies as a Resource for the Utah Startup Office. Thank you!)', 'community', NULLIF('https://comtel.zohobackstage.com/aistratagy#/?lang=en', ''), NULLIF('njohnson@comtelut.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['any', 'other']::text[], ARRAY['Salt Lake']::text[]),
    ('3770', 'First Step Entrepreneur', 'First Step Entrepreneur (FSTEP) is a 6-week, action-first online program for aspiring entrepreneurs, particularly those who don''t have a business idea yet. Unlike traditional courses, FSTEP is a live cohort experience focused on building foundational skills and confidence through a series of practical challenges, peer support, and accountability. It''s designed as a "practice field, not a university course." The Founding Cohort is currently open for applications at a one-time price of $499 (future standard price $1,499) and includes a "Prove It to Yourself" full refund guarantee.', 'community', NULLIF('https://firststepentrepreneur.com/', ''), NULLIF('art@artharrisonofficial.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['validation']::text[], ARRAY['any', 'entrepreneurship-communities']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3771', 'FSTEP Idea Explorer', 'A free interactive tool for aspiring Utah entrepreneurs to discover unique business concepts by combining personal interests, skills, and market problems. No signup required.', 'mentor', NULLIF('https://firststepentrepreneur.com/app/', ''), NULLIF('art@artharrisonofficial.com', ''), ARRAY['Any']::text[], ARRAY['aerospace and defense', 'agriculture', 'arts and entertainment and recreation', 'consumer packaged goods', 'financial services', 'hospitality and food services', 'life sciences and healthcare', 'manufacturing', 'other', 'software and information technology']::text[], ARRAY['idea', 'validation']::text[], ARRAY['any', 'start-a-business']::text[], ARRAY['Beaver', 'Box Elder', 'Cache', 'Carbon', 'Daggett', 'Davis', 'Duchesne', 'Emery', 'Garfield', 'Grand', 'Iron', 'Juab', 'Kane', 'Millard', 'Morgan', 'Piute', 'Rich', 'Salt Lake', 'San Juan', 'Sanpete', 'Sevier', 'Summit', 'Tooele', 'Uintah', 'Utah', 'Wasatch', 'Washington', 'Wayne', 'Weber']::text[]),
    ('3783', 'A-Tech home plans', 'A‑TECH Home Plans is a Utah-based residential design firm with over 20 years of experience and 400+ completed projects. Specializing in custom homes, remodels, ADUs, and additions, we provide tailored design solutions that blend creativity, functionality, and local building expertise. From concept to construction plans, we help bring your vision to life—efficiently and affordably.', 'community', NULLIF('https://atechhomeplans.com/', ''), NULLIF('enperetti2007@gmail.com', ''), ARRAY['Rural']::text[], ARRAY['other']::text[], ARRAY['validation']::text[], ARRAY['other', 'rural']::text[], ARRAY['Davis']::text[])
),
normalized AS (
  SELECT
    legacy_id,
    name,
    description,
    category::resource_category AS category,
    website,
    contact_email,
    communities,
    industry_fit,
    stage_fit,
    tags,
    locations,
    locations[1] AS primary_location,
    (
      substr(md5('resource-csv:' || legacy_id), 1, 8) || '-' ||
      substr(md5('resource-csv:' || legacy_id), 9, 4) || '-' ||
      substr(md5('resource-csv:' || legacy_id), 13, 4) || '-' ||
      substr(md5('resource-csv:' || legacy_id), 17, 4) || '-' ||
      substr(md5('resource-csv:' || legacy_id), 21, 12)
    )::uuid AS resource_id
  FROM resource_source
),
normalized_unique AS (
  SELECT DISTINCT ON (name)
    legacy_id,
    name,
    description,
    category,
    website,
    contact_email,
    communities,
    industry_fit,
    stage_fit,
    tags,
    locations,
    primary_location,
    resource_id
  FROM normalized
  ORDER BY name, legacy_id
),
upsert_resources AS (
  INSERT INTO startup_resources (
    id,
    name,
    category,
    description,
    source_external_id,
    website,
    contact_email,
    communities,
    address,
    city,
    state,
    lat,
    lng,
    location,
    stage_fit,
    industry_fit,
    tags
  )
  SELECT
    n.resource_id,
    n.name,
    n.category,
    n.description,
    n.legacy_id,
    n.website,
    n.contact_email,
    n.communities,
    CONCAT(n.primary_location, ' County, UT') AS address,
    n.primary_location AS city,
    'UT' AS state,
    cc.lat,
    cc.lng,
    ST_SetSRID(ST_MakePoint(cc.lng, cc.lat), 4326),
    n.stage_fit,
    n.industry_fit,
    n.tags
  FROM normalized_unique n
  JOIN county_centroids cc ON cc.county = n.primary_location
  ON CONFLICT (name) DO UPDATE SET
    category = EXCLUDED.category,
    description = EXCLUDED.description,
    source_external_id = EXCLUDED.source_external_id,
    website = EXCLUDED.website,
    contact_email = EXCLUDED.contact_email,
    communities = EXCLUDED.communities,
    address = EXCLUDED.address,
    city = EXCLUDED.city,
    state = EXCLUDED.state,
    lat = EXCLUDED.lat,
    lng = EXCLUDED.lng,
    location = EXCLUDED.location,
    stage_fit = EXCLUDED.stage_fit,
    industry_fit = EXCLUDED.industry_fit,
    tags = EXCLUDED.tags,
    updated_at = NOW()
  RETURNING id, source_external_id
),
resource_id_map AS (
  SELECT id, source_external_id FROM upsert_resources
  UNION
  SELECT sr.id, sr.source_external_id
  FROM startup_resources sr
  JOIN normalized_unique n ON n.legacy_id = sr.source_external_id
)
INSERT INTO startup_resource_locations (
  resource_id,
  location_name,
  address,
  city,
  state,
  lat,
  lng,
  location,
  is_primary
)
SELECT
  rim.id,
  location_name.county AS location_name,
  CONCAT(location_name.county, ' County, UT') AS address,
  location_name.county AS city,
  'UT' AS state,
  cc.lat,
  cc.lng,
  ST_SetSRID(ST_MakePoint(cc.lng, cc.lat), 4326),
  (
    location_name.ordinality = 1
    AND NOT EXISTS (
      SELECT 1
      FROM startup_resource_locations existing_primary
      WHERE existing_primary.resource_id = rim.id
        AND existing_primary.is_primary = TRUE
    )
  ) AS is_primary
FROM normalized_unique n
JOIN resource_id_map rim ON rim.source_external_id = n.legacy_id
CROSS JOIN LATERAL (
  SELECT county, MIN(ordinality) AS ordinality
  FROM unnest(n.locations) WITH ORDINALITY AS raw_location(county, ordinality)
  GROUP BY county
) AS location_name
JOIN county_centroids cc ON cc.county = location_name.county
ON CONFLICT (resource_id, location_name) DO UPDATE SET
  address = EXCLUDED.address,
  city = EXCLUDED.city,
  state = EXCLUDED.state,
  lat = EXCLUDED.lat,
  lng = EXCLUDED.lng,
  location = EXCLUDED.location,
  is_primary = EXCLUDED.is_primary,
  updated_at = NOW();
